                    >
                      <option value={RegistrationStatus.UNDER_PROCESS}>Under Process</option>
                      <option value={RegistrationStatus.REGISTERED}>Registered</option>
                    </select>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredStudents.length === 0 && (
            <div className="p-12 text-center text-slate-400">
