              </div>
            )}
          </div>
        </>
      )}

      {activeTab === 'requests' && (
        <div className="space-y-4">
          {requests.length > 0 && (
            <div className="flex items-center gap-3 px-4 py-2 mb-2 bg-slate-50 rounded-xl border border-slate-200 w-fit">
              <button 
