                      }`}>
                        {request.requestType}
                      </span>
                      <span className="text-xs text-slate-400 font-medium">Submitted {new Date(request.createdAt).toLocaleDateString()}</span>
                    </div>
                    <h3 className="font-bold text-slate-900">{request.studentName} <span className="text-slate-400 text-sm font-normal">({request.studentId})</span></h3>
                    <p className="text-slate-600 mt-2 text-sm leading-relaxed">{request.details}</p>
                  </div>

                  <div className="flex items-center gap-4">
                    {request.status === 'Processed' ? (
                      <span className="flex items-center gap-1.5 text-emerald-600 font-bold bg-emerald-50 px-4 py-2 rounded-xl border border-emerald-100">
                        <CheckCircle2 size={18} />
                        Finished
                      </span>
                    ) : (
                      <button 
                        onClick={() => processRequest(request.id)}
                        className="px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-xl hover:bg-slate-50 transition-colors font-bold text-sm shadow-sm"
                      >
                        Mark Finished
                      </button>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Search history by ID, Name, Action or Event Type..."
              value={logSearch}
              onChange={(e) => setLogSearch(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-white border border-slate-200 rounded-2xl shadow-sm focus:ring-2 focus:ring-sky-500 outline-none transition-all font-medium"
            />
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
              <h3 className="font-bold text-slate-900 flex items-center gap-2">
                <History size={18} className="text-sky-600" />
                Student Activity History Log
              </h3>
              <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">{filteredLogs.length} Events Total</span>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                  <tr>
                    <th className="px-6 py-4">Date & Time</th>
                    <th className="px-6 py-4">Student ID</th>
                    <th className="px-6 py-4">Student Name</th>
                    <th className="px-6 py-4">Event Type</th>
                    <th className="px-6 py-4">Action Details</th>
                    <th className="px-6 py-4">Actor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-slate-700">
                  {filteredLogs.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="p-20 text-center text-slate-400">
                        <History size={48} className="mx-auto mb-4 opacity-10" />
                        <p className="font-medium">No activity log entries found.</p>
                      </td>
                    </tr>
                  ) : (
                    filteredLogs.map((log) => (
                      <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-2 text-xs font-medium text-slate-500">
                            <Calendar size={12} className="text-slate-400" />
                            {new Date(log.timestamp).toLocaleDateString()}
                          </div>
                          <div className="flex items-center gap-2 text-[10px] text-slate-400 ml-5">
                            <Clock size={10} />
                            {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className="font-mono text-xs font-bold text-slate-900 bg-slate-100 px-2 py-1 rounded">
                            {log.studentId || 'SYSTEM'}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <div className="font-semibold text-sm text-slate-800">
                            {log.studentName || 'System Process'}
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                            log.type === 'Admission' ? 'bg-sky-100 text-sky-700' :
                            log.type === 'Placement' ? 'bg-indigo-100 text-indigo-700' :
                            log.type === 'StatusUpdate' ? 'bg-emerald-100 text-emerald-700' :
                            'bg-amber-100 text-amber-700'
                          }`}>
                            {log.type}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-sm text-slate-600 max-w-xs truncate" title={log.description}>
                            {log.description}
                          </p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-2">
                            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold ${
                              log.actor === 'Registrar' ? 'bg-slate-800 text-white' : 'bg-amber-100 text-amber-700'
                            }`}>
                              {log.actor.charAt(0)}
                            </div>
                            <span className="text-xs font-bold text-slate-600">{log.actor}</span>
                          </div>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* Bulk Action Toolbar */}
      {anySelected && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-6 z-50 border border-slate-700 animate-in fade-in slide-in-from-bottom-4">
          <div className="flex items-center gap-3 pr-6 border-r border-slate-700">
            <div className="w-8 h-8 bg-sky-500 rounded-lg flex items-center justify-center font-bold text-sm">
              {activeTab === 'students' ? selectedIds.length : selectedRequestIds.length}
            </div>
            <span className="text-sm font-semibold">{activeTab === 'students' ? 'Students' : 'Requests'} Selected</span>
          </div>
          <div className="flex items-center gap-3">
            <span className="text-xs text-slate-400 font-bold uppercase tracking-wider">Bulk Actions:</span>

            {activeTab === 'students' ? (
              <>
                <button 
                  onClick={() => handleBulkStatusUpdate(RegistrationStatus.REGISTERED)}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-500 rounded-xl text-sm font-bold transition-colors"
                >
                  <CheckCircle2 size={16} />
                  Mark Registered
                </button>
                <button 
                  onClick={() => handleBulkStatusUpdate(RegistrationStatus.UNDER_PROCESS)}
                  className="flex items-center gap-2 px-4 py-2 bg-amber-600 hover:bg-amber-500 rounded-xl text-sm font-bold transition-colors"
                >
                  <Clock size={16} />
                  Mark Under Process
                </button>
              </>
            ) : (
              <button 
                onClick={handleBulkRequestProcess}
                className="flex items-center gap-2 px-4 py-2 bg-sky-600 hover:bg-sky-500 rounded-xl text-sm font-bold transition-colors"
              >
                <CheckCircle size={16} />
                Mark all as Finished
              </button>
            )}

            <button 
              onClick={() => activeTab === 'students' ? setSelectedIds([]) : setSelectedRequestIds([])}
              className="px-4 py-2 text-slate-400 hover:text-white text-sm font-medium"
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default RegistrarDashboard;

import React, { useState, useMemo } from 'react';
import { Student, AcademicLevel, RegistrationStatus, ScheduleRequest, ActivityLog } from '../types';
import { FileUp, Send, CheckCircle2, History, Info, LayoutList, MessageSquarePlus, Download, Search, Hash, Book } from 'lucide-react';
import * as XLSX from 'xlsx';

interface PrepDashboardProps {
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  requests: ScheduleRequest[];
  setRequests: React.Dispatch<React.SetStateAction<ScheduleRequest[]>>;
  addLog: (type: ActivityLog['type'], description: string, actor: string, studentId?: string, studentName?: string) => void;
}

const COURSE_LIST = [
  'ENGL001', 'ENGL002', 'ENGL005', 
  'MATH001', 'MATH012', 
  'PYP 001', 'PYP 002', 
  'Modular Courses', 
  'PE 001', 'PE 002'
];

const PrepDashboard: React.FC<PrepDashboardProps> = ({ students, setStudents, requests, setRequests, addLog }) => {
  const [activeTab, setActiveTab] = useState<'placement' | 'adjustments'>('placement');
  const [selectedStudentId, setSelectedStudentId] = useState('');
  const [requestType, setRequestType] = useState<'Section Change' | 'English Shift'>('Section Change');
  const [requestDetails, setRequestDetails] = useState('');

  const [sectionNumber, setSectionNumber] = useState('');
  const [courseName, setCourseName] = useState('');

  const [statusSearch, setStatusSearch] = useState('');
  const [requestSearch, setRequestSearch] = useState('');

  const selectedStudent = useMemo(() => 
    students.find(s => s.id === selectedStudentId), 
    [students, selectedStudentId]
  );

  const isPrepSectionChange = selectedStudent?.academicLevel === AcademicLevel.PREP && requestType === 'Section Change';

  const handlePlacementUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        setStudents(prev => {
          const updatedStudents = [...prev];
          let updateCount = 0;
          let newCount = 0;

          data.forEach((row: any) => {
            const rowId = String(row.ID || row.id || '');
            if (!rowId) return;

            const eng = String(row.English || row.english || 'ENGL001');
            const math = String(row.Math || row.math || 'MATH001');

            const engSec = row['English Section'] || row.english_section ? String(row['English Section'] || row.english_section) : undefined;
            const mathSec = row['Math Section'] || row.math_section ? String(row['Math Section'] || row.math_section) : undefined;

            const isPromoted = eng.toLowerCase() === 'promoted' && math.toLowerCase() === 'promoted';
            const level = isPromoted ? AcademicLevel.FRESHMAN : AcademicLevel.PREP;

            const existingIndex = updatedStudents.findIndex(s => s.id === rowId);

            if (existingIndex !== -1) {
              updatedStudents[existingIndex] = {
                ...updatedStudents[existingIndex],
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec || updatedStudents[existingIndex].englishSection,
                mathSection: mathSec || updatedStudents[existingIndex].mathSection,
                updatedAt: new Date().toISOString()
              };
              updateCount++;
              addLog('Placement', `Updated English (${eng}) and Math (${math}) placements.`, 'Prep Dept', rowId, updatedStudents[existingIndex].name);
            } else {
              const newName = String(row.Name || row.name || 'External Record');
              updatedStudents.push({
                id: rowId,
                name: newName,
                gender: 'Male',
                admittedMajor: 'Not Provided',
                term: '241',
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec,
                mathSection: mathSec,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              });
              newCount++;
              addLog('Placement', `Created new placement record: E:${eng}, M:${math}.`, 'Prep Dept', rowId, newName);
            }
          });

          alert(`Placement update complete: ${updateCount} students updated, ${newCount} new records created.`);
          return updatedStudents;
        });

      } catch (err) {
        console.error(err);
        alert("Error parsing file. Ensure columns include ID, English, Math, 'English Section', and 'Math Section'.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const downloadPlacementTemplate = () => {
    const templateData = [
      { ID: '20241001', English: 'Promoted', Math: 'MATH001', 'English Section': '45', 'Math Section': '55' },
      { ID: '20241002', English: 'ENGL001', Math: 'Promoted', 'English Section': '10', 'Math Section': '20' }
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Placements");
    XLSX.writeFile(wb, "Student_Placement_Template.xlsx");
  };

  const handleSubmitRequest = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStudent) {
      alert("Student ID not found.");
      return;
    }

    let finalDetails = requestDetails;
    if (isPrepSectionChange) {
      finalDetails = `[COURSE: ${courseName} | NEW SECTION: ${sectionNumber}]${requestDetails ? ' - ' + requestDetails : ''}`;
    }

    const newRequest: ScheduleRequest = {
      id: Math.random().toString(36).substr(2, 9),
      studentId: selectedStudent.id,
      studentName: selectedStudent.name,
      requestType,
      details: finalDetails || 'No justification provided.',
      courseName: isPrepSectionChange ? courseName : undefined,
      sectionNumber: isPrepSectionChange ? sectionNumber : undefined,
      status: 'Pending',
      createdAt: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    addLog('Adjustment', `Submitted ${requestType}: ${finalDetails || 'Request sent.'}`, 'Prep Dept', selectedStudent.id, selectedStudent.name);

    setRequestDetails('');
    setSectionNumber('');
    setCourseName('');
    setSelectedStudentId('');
    setRequestSearch('');
    alert("Schedule adjustment request sent to Registrar.");
  };

  const filteredStatusStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(statusSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(statusSearch.toLowerCase())
    );
  }, [students, statusSearch]);

  const filteredRequestStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(requestSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(requestSearch.toLowerCase())
    );
  }, [students, requestSearch]);

  const isSubmitDisabled = !selectedStudentId || (isPrepSectionChange && (!sectionNumber || !courseName));

  return (
    <div className="space-y-6">
      <div className="flex gap-4 border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('placement')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'placement' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <FileUp size={18} />
          Placement Control
        </button>
        <button 
          onClick={() => setActiveTab('adjustments')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'adjustments' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <MessageSquarePlus size={18} />
          Schedule Adjustments
        </button>
      </div>

      {activeTab === 'placement' ? (
        <div className="grid grid-cols-1 gap-8">
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-sky-100 text-sky-600 rounded-lg"><FileUp size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">Placement Processing</h2>
                  <p className="text-sm text-slate-500">Update existing students with test results</p>
                </div>
              </div>
              <button 
                onClick={downloadPlacementTemplate}
                className="flex items-center gap-2 text-xs font-bold text-sky-600 bg-sky-50 px-3 py-2 rounded-lg hover:bg-sky-100 transition-colors"
              >
                <Download size={14} />
                Download Placement Template
              </button>
            </div>

            <div className="grid grid-cols-1 gap-8">
              <div className="border-2 border-dashed border-slate-200 rounded-2xl p-10 text-center space-y-4 hover:border-sky-300 transition-colors bg-slate-50/30 group">
                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto text-slate-400 shadow-sm border border-slate-100 group-hover:scale-110 transition-transform">
                  <FileUp size={32} className="group-hover:text-sky-500" />
                </div>
                <div>
                  <p className="font-semibold text-slate-700">Drop Placement Excel here</p>
                  <p className="text-sm text-slate-400">Include 'English Section' and 'Math Section' columns</p>
                </div>
                <label className="inline-block px-6 py-3 bg-slate-900 text-white rounded-xl cursor-pointer hover:bg-slate-800 transition-all font-medium shadow-lg shadow-slate-200">
                  Import Test Results
                  <input type="file" className="hidden" onChange={handlePlacementUpload} accept=".xlsx, .xls, .csv" />
                </label>
              </div>
            </div>
          </div>

          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
             <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><History size={24} /></div>
                  <h2 className="text-xl font-bold text-slate-900">Live Status Monitor</h2>
                </div>
                <div className="relative w-full md:w-72">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <input
                    type="text"
                    placeholder="Search student by Name or ID..."
                    value={statusSearch}
                    onChange={(e) => setStatusSearch(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-sm font-medium text-slate-500"
                  />
                </div>
             </div>

             <div className="overflow-x-auto rounded-xl border border-slate-100">
               <table className="w-full text-left">
                 <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                   <tr>
                     <th className="px-6 py-4">Student</th>
                     <th className="px-6 py-4">Placement</th>
                     <th className="px-6 py-4">Section Number</th>
                     <th className="px-6 py-4">Academic Level</th>
                     <th className="px-6 py-4 text-center">Status</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                   {filteredStatusStudents.length === 0 ? (
                     <tr>
                       <td colSpan={5} className="px-6 py-12 text-center text-slate-400 font-medium">
                         No students found matching your search.
                       </td>
                     </tr>
                   ) : (
                     filteredStatusStudents.map(s => (
                       <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                         <td className="px-6 py-4">
                            <div className="font-bold text-slate-900">{s.name}</div>
                            <div className="text-xs text-slate-400 font-mono font-bold uppercase">{s.id}</div>
                         </td>
                         <td className="px-6 py-4">
                            <div className="flex gap-2">
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">E: {s.englishPlacement}</span>
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">M: {s.mathPlacement}</span>
                            </div>
                         </td>
                         <td className="px-6 py-4">
                           <span className="text-sm font-mono font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">
                             E:{s.englishSection || '-'} M:{s.mathSection || '-'}
                           </span>
                         </td>
                         <td className="px-6 py-4">
                           <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${s.academicLevel === 'Prep' ? 'bg-indigo-100 text-indigo-700' : 'bg-emerald-100 text-emerald-700'}`}>
                              {s.academicLevel}
                           </span>
                         </td>
                         <td className="px-6 py-4 text-center">
                            <span className={`inline-flex items-center gap-1.5 text-xs font-bold ${s.status === RegistrationStatus.REGISTERED ? 'text-emerald-600' : 'text-amber-600'}`}>
                               {s.status === RegistrationStatus.REGISTERED ? <CheckCircle2 size={14} /> : <div className="w-3.5 h-3.5 border-2 border-amber-600 border-t-transparent rounded-full animate-spin"></div>}
                               {s.status}
                            </span>
                         </td>
                       </tr>
                     ))
                   )}
                 </tbody>
               </table>
             </div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 sticky top-24">
              <div className="flex items-center gap-3 mb-6">
                <div className="p-2 bg-amber-100 text-amber-600 rounded-lg"><Send size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">New Request</h2>
                  <p className="text-sm text-slate-500">Submit adjustment to Registrar</p>
                </div>
              </div>

              <form onSubmit={handleSubmitRequest} className="space-y-5">
                <div className="space-y-2">
                  <label className="block text-sm font-bold text-slate-700">Target Student</label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                    <input
                      type="text"
                      placeholder="Type name or ID to filter..."
                      value={requestSearch}
                      onChange={(e) => setRequestSearch(e.target.value)}
                      className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-t-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-xs font-medium text-slate-500"
                    />
                  </div>
                  <select 
                    value={selectedStudentId}
                    onChange={(e) => setSelectedStudentId(e.target.value)}
                    className="w-full p-3 bg-white border border-t-0 border-slate-200 rounded-b-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all font-medium text-slate-700 text-sm"
                    size={5}
                  >
                    <option value="" disabled className="text-slate-400">Select from results...</option>
                    {filteredRequestStudents.length === 0 ? (
                      <option disabled>No students found</option>
                    ) : (
                      filteredRequestStudents.map(s => (
                        <option key={s.id} value={s.id}>{s.id} - {s.name}</option>
                      ))
                    )}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5">Request Type</label>
                  <div className="flex flex-col gap-2">
                    {(['Section Change', 'English Shift'] as const).map(type => (
                      <button
                        key={type}
                        type="button"
                        onClick={() => setRequestType(type)}
                        className={`p-3 text-sm font-bold rounded-xl border text-left transition-all ${
                          requestType === type 
                            ? 'bg-sky-600 border-sky-600 text-white shadow-md shadow-sky-100' 
                            : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                        }`}
                      >
                        {type}
                      </button>
                    ))}
                  </div>
                </div>

                {isPrepSectionChange && (
                  <div className="space-y-4 p-4 bg-sky-50 rounded-xl border border-sky-100 animate-in fade-in slide-in-from-top-2">
                    <div className="flex items-center gap-2 text-sky-700 font-bold text-xs uppercase mb-1">
                      <Info size={14} />
                      Prep Details Required
                    </div>
                    <div className="space-y-3">
                      <div>
                        <label className="block text-[10px] font-black text-sky-600 uppercase mb-1">Course Name</label>
                        <div className="relative">
                          <Book className="absolute left-3 top-1/2 -translate-y-1/2 text-sky-400" size={14} />
                          <select
                            value={courseName}
                            onChange={(e) => setCourseName(e.target.value)}
                            className="w-full pl-9 pr-3 py-2 bg-white border border-sky-200 rounded-lg text-sm font-semibold text-slate-500 focus:ring-2 focus:ring-sky-400 outline-none"
                          >
                            <option value="">Select Course...</option>
                            {COURSE_LIST.map(course => (
                              <option key={course} value={course}>{course}</option>
                            ))}
                          </select>
                        </div>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-sky-600 uppercase mb-1">Target Section</label>
                        <div className="relative">
                          <Hash className="absolute left-3 top-1/2 -translate-y-1/2 text-sky-400" size={14} />
                          <input
                            type="text"
                            placeholder="e.g. 104"
                            value={sectionNumber}
                            onChange={(e) => setSectionNumber(e.target.value)}
                            className="w-full pl-9 pr-3 py-2 bg-white border border-sky-200 rounded-lg text-sm font-semibold text-slate-500 focus:ring-2 focus:ring-sky-400 outline-none"
                          />
                        </div>
                      </div>
                    </div>
                  </div>
                )}

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5">Specific Justification <span className="text-slate-400 font-normal">(Optional)</span></label>
                  <textarea
                    value={requestDetails}
                    onChange={(e) => setRequestDetails(e.target.value)}
                    placeholder="Provide additional details or reasons..."
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all h-24 resize-none text-slate-500 font-medium"
                  />
                </div>

                <button
                  type="submit"
                  disabled={isSubmitDisabled}
                  className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-slate-200 flex items-center justify-center gap-2"
                >
                  <Send size={18} />
                  Send to Registrar
                </button>
              </form>
            </div>
          </div>

          <div className="lg:col-span-2 space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
               <div className="flex items-center justify-between mb-8">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-100 text-slate-600 rounded-lg"><LayoutList size={24} /></div>
                    <h2 className="text-xl font-bold text-slate-900">Recent History</h2>
                  </div>
               </div>

               <div className="space-y-4">
                 {requests.length === 0 ? (
                   <div className="text-center py-20 bg-slate-50 rounded-2xl border border-dashed border-slate-200 text-slate-400">
                      <LayoutList size={40} className="mx-auto mb-4 opacity-20" />
                      <p className="font-medium">No adjustment requests submitted yet</p>
                   </div>
                 ) : (
                   requests.map((request) => (
                     <div key={request.id} className="bg-slate-50 rounded-2xl p-6 border border-slate-200 hover:bg-white hover:shadow-md transition-all">
                        <div className="flex justify-between items-start mb-4">
                           <div className="flex items-center gap-2">
                              <span className={`px-2.5 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                                request.status === 'Processed' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                              }`}>
                                {request.status === 'Processed' ? 'FINISHED' : 'PENDING REGISTRAR'}
                              </span>
                              <span className="text-[10px] font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-100">
                                #{request.id}
                              </span>
                           </div>
                           <span className="text-xs font-medium text-slate-400">
                             {new Date(request.createdAt).toLocaleDateString()} at {new Date(request.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                           </span>
                        </div>

                        <div className="mb-3">
                          <h4 className="font-black text-slate-900">{request.studentName} <span className="text-slate-400 text-sm font-normal">({request.studentId})</span></h4>
                          <span className="text-[11px] font-bold text-sky-600 bg-sky-50 px-2 py-0.5 rounded border border-sky-100 inline-block mt-1">
                            {request.requestType}
                          </span>
                        </div>

                        <p className="text-sm text-slate-600 leading-relaxed bg-white/50 p-3 rounded-xl border border-slate-100 italic">
                          "{request.details}"
                        </p>

                        {request.status === 'Processed' && (
                          <div className="mt-4 flex items-center gap-2 text-xs font-bold text-emerald-600">
                             <CheckCircle2 size={16} />
                             Registrar has completed this adjustment
                          </div>
                        )}
                     </div>
                   ))
                 )}
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PrepDashboard;

import React, { useState, useMemo } from 'react';
import { Student, AcademicLevel, RegistrationStatus, ScheduleRequest, ActivityLog } from '../types';
import { FileUp, Send, CheckCircle2, History, Info, LayoutList, MessageSquarePlus, Download, Search, Hash, Book } from 'lucide-react';
import * as XLSX from 'xlsx';

interface PrepDashboardProps {
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  requests: ScheduleRequest[];
  setRequests: React.Dispatch<React.SetStateAction<ScheduleRequest[]>>;
  addLog: (type: ActivityLog['type'], description: string, actor: string, studentId?: string, studentName?: string) => void;
}

const COURSE_LIST = [
  'ENGL001', 'ENGL002', 'ENGL005', 
  'MATH001', 'MATH012', 
  'PYP 001', 'PYP 002', 
  'Modular Courses', 
  'PE 001', 'PE 002'
];

const PrepDashboard: React.FC<PrepDashboardProps> = ({ students, setStudents, requests, setRequests, addLog }) => {
  const [activeTab, setActiveTab] = useState<'placement' | 'adjustments'>('placement');
  const [selectedStudentId, setSelectedStudentId] = useState('');
  const [requestType, setRequestType] = useState<'Section Change' | 'English Shift'>('Section Change');
  const [requestDetails, setRequestDetails] = useState('');

  const [sectionNumber, setSectionNumber] = useState('');
  const [courseName, setCourseName] = useState('');

  const [statusSearch, setStatusSearch] = useState('');
  const [requestSearch, setRequestSearch] = useState('');

  const selectedStudent = useMemo(() => 
    students.find(s => s.id === selectedStudentId), 
    [students, selectedStudentId]
  );

  const isPrepSectionChange = selectedStudent?.academicLevel === AcademicLevel.PREP && requestType === 'Section Change';

  const handlePlacementUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        setStudents(prev => {
          const updatedStudents = [...prev];
          let updateCount = 0;
          let newCount = 0;

          data.forEach((row: any) => {
            const rowId = String(row.ID || row.id || '');
            if (!rowId) return;

            const eng = String(row.English || row.english || 'ENGL001');
            const math = String(row.Math || row.math || 'MATH001');

            const engSec = row['English Section'] || row.english_section ? String(row['English Section'] || row.english_section) : undefined;
            const mathSec = row['Math Section'] || row.math_section ? String(row['Math Section'] || row.math_section) : undefined;

            const isPromoted = eng.toLowerCase() === 'promoted' && math.toLowerCase() === 'promoted';
            const level = isPromoted ? AcademicLevel.FRESHMAN : AcademicLevel.PREP;

            const existingIndex = updatedStudents.findIndex(s => s.id === rowId);

            if (existingIndex !== -1) {
              // Any update to existing student resets status to Under Process
              updatedStudents[existingIndex] = {
                ...updatedStudents[existingIndex],
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec || updatedStudents[existingIndex].englishSection,
                mathSection: mathSec || updatedStudents[existingIndex].mathSection,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              };
              updateCount++;
              addLog('Placement', `Updated data & reset status to Under Process (Wait for Registrar).`, 'Prep Dept', rowId, updatedStudents[existingIndex].name);
            } else {
              const newName = String(row.Name || row.name || 'External Record');
              updatedStudents.push({
                id: rowId,
                name: newName,
                gender: 'Male',
                admittedMajor: 'Not Provided',
                term: '241',
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec,
                mathSection: mathSec,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              });
              newCount++;
              addLog('Placement', `Created new placement record. Status: Under Process.`, 'Prep Dept', rowId, newName);
            }
          });

          alert(`Placement update complete: ${updateCount} students updated (Status reset to Under Process), ${newCount} new records created.`);
          return updatedStudents;
        });

      } catch (err) {
        console.error(err);
        alert("Error parsing file. Ensure columns include ID, English, Math, 'English Section', and 'Math Section'.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const downloadPlacementTemplate = () => {
    const templateData = [
      { ID: '20241001', English: 'Promoted', Math: 'MATH001', 'English Section': '45', 'Math Section': '55' },
      { ID: '20241002', English: 'ENGL001', Math: 'Promoted', 'English Section': '10', 'Math Section': '20' }
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Placements");
    XLSX.writeFile(wb, "Student_Placement_Template.xlsx");
  };

  const handleSubmitRequest = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStudent) {
      alert("Student ID not found.");
      return;
    }

    let finalDetails = requestDetails;
    if (isPrepSectionChange) {
      finalDetails = `[COURSE: ${courseName} | NEW SECTION: ${sectionNumber}]${requestDetails ? ' - ' + requestDetails : ''}`;
    }

    const newRequest: ScheduleRequest = {
      id: Math.random().toString(36).substr(2, 9),
      studentId: selectedStudent.id,
      studentName: selectedStudent.name,
      requestType,
      details: finalDetails || 'No justification provided.',
      courseName: isPrepSectionChange ? courseName : undefined,
      sectionNumber: isPrepSectionChange ? sectionNumber : undefined,
      status: 'Pending',
      createdAt: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    addLog('Adjustment', `Submitted ${requestType}: ${finalDetails || 'Request sent.'}`, 'Prep Dept', selectedStudent.id, selectedStudent.name);

    setRequestDetails('');
    setSectionNumber('');
    setCourseName('');
    setSelectedStudentId('');
    setRequestSearch('');
    alert("Schedule adjustment request sent to Registrar.");
  };

  const filteredStatusStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(statusSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(statusSearch.toLowerCase())
    );
  }, [students, statusSearch]);

  const filteredRequestStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(requestSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(requestSearch.toLowerCase())
    );
  }, [students, requestSearch]);

  const isSubmitDisabled = !selectedStudentId || (isPrepSectionChange && (!sectionNumber || !courseName));

  return (
    <div className="space-y-6">
      <div className="flex gap-4 border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('placement')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'placement' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <FileUp size={18} />
          Placement Control
        </button>
        <button 
          onClick={() => setActiveTab('adjustments')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'adjustments' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <MessageSquarePlus size={18} />
          Schedule Adjustments
        </button>
      </div>

      {activeTab === 'placement' ? (
        <div className="grid grid-cols-1 gap-8">
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-sky-100 text-sky-600 rounded-lg"><FileUp size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">Placement Processing</h2>
                  <p className="text-sm text-slate-500">Update existing students with test results</p>
                </div>
              </div>
              <button 
                onClick={downloadPlacementTemplate}
                className="flex items-center gap-2 text-xs font-bold text-sky-600 bg-sky-50 px-3 py-2 rounded-lg hover:bg-sky-100 transition-colors"
              >
                <Download size={14} />
                Download Placement Template
              </button>
            </div>

            <div className="grid grid-cols-1 gap-8">
              <div className="border-2 border-dashed border-slate-200 rounded-2xl p-10 text-center space-y-4 hover:border-sky-300 transition-colors bg-slate-50/30 group">
                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto text-slate-400 shadow-sm border border-slate-100 group-hover:scale-110 transition-transform">
                  <FileUp size={32} className="group-hover:text-sky-500" />
                </div>
                <div>
                  <p className="font-semibold text-slate-700">Drop Placement Excel here</p>
                  <p className="text-sm text-slate-400">Include 'English Section' and 'Math Section' columns</p>
                </div>
                <label className="inline-block px-6 py-3 bg-slate-900 text-white rounded-xl cursor-pointer hover:bg-slate-800 transition-all font-medium shadow-lg shadow-slate-200">
                  Import Test Results
                  <input type="file" className="hidden" onChange={handlePlacementUpload} accept=".xlsx, .xls, .csv" />
                </label>
              </div>
            </div>
          </div>

          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
             <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><History size={24} /></div>
                  <h2 className="text-xl font-bold text-slate-900">Live Status Monitor</h2>
                </div>
                <div className="relative w-full md:w-72">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <input
                    type="text"
                    placeholder="Search student by Name or ID..."
                    value={statusSearch}
                    onChange={(e) => setStatusSearch(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-sm font-medium text-slate-500"
                  />
                </div>
             </div>

             <div className="overflow-x-auto rounded-xl border border-slate-100">
               <table className="w-full text-left">
                 <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                   <tr>
                     <th className="px-6 py-4">Student</th>
                     <th className="px-6 py-4">Placement</th>
                     <th className="px-6 py-4">Section Number</th>
                     <th className="px-6 py-4">Academic Level</th>
                     <th className="px-6 py-4 text-center">Status</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                   {filteredStatusStudents.length === 0 ? (
                     <tr>
                       <td colSpan={5} className="px-6 py-12 text-center text-slate-400 font-medium">
                         No students found matching your search.
                       </td>
                     </tr>
                   ) : (
                     filteredStatusStudents.map(s => (
                       <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                         <td className="px-6 py-4">
                            <div className="font-bold text-slate-900">{s.name}</div>
                            <div className="text-xs text-slate-400 font-mono font-bold uppercase">{s.id}</div>
                         </td>
                         <td className="px-6 py-4">
                            <div className="flex gap-2">
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">E: {s.englishPlacement}</span>
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">M: {s.mathPlacement}</span>
                            </div>
                         </td>
                         <td className="px-6 py-4">
                           <span className="text-sm font-mono font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">
                             E:{s.englishSection || '-'} M:{s.mathSection || '-'}
                           </span>
                         </td>
                         <td className="px-6 py-4">
                           <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${s.academicLevel === 'Prep' ? 'bg-indigo-100 text-indigo-700' : 'bg-emerald-100 text-emerald-700'}`}>
                              {s.academicLevel}
                           </span>
                         </td>
                         <td className="px-6 py-4 text-center">
                            <span className={`inline-flex items-center gap-1.5 text-xs font-bold ${s.status === RegistrationStatus.REGISTERED ? 'text-emerald-600' : 'text-amber-600'}`}>
                               {s.status === RegistrationStatus.REGISTERED ? <CheckCircle2 size={14} /> : <div className="w-3.5 h-3.5 border-2 border-amber-600 border-t-transparent rounded-full animate-spin"></div>}
                               {s.status}
                            </span>
                         </td>
                       </tr>
                     ))
                   )}
                 </tbody>
               </table>
             </div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 sticky top-24">
              <div className="flex items-center gap-3 mb-6">
                <div className="p-2 bg-amber-100 text-amber-600 rounded-lg"><Send size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">New Request</h2>
                  <p className="text-sm text-slate-500">Submit adjustment to Registrar</p>
                </div>
              </div>

              <form onSubmit={handleSubmitRequest} className="space-y-5">
                <div className="space-y-2">
                  <label className="block text-sm font-bold text-slate-700">Target Student</label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                    <input
                      type="text"
                      placeholder="Type name or ID to filter..."
                      value={requestSearch}
                      onChange={(e) => setRequestSearch(e.target.value)}
                      className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-t-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-xs font-medium text-slate-500"
                    />
                  </div>
                  <select 
                    value={selectedStudentId}
                    onChange={(e) => setSelectedStudentId(e.target.value)}
                    className="w-full p-3 bg-white border border-t-0 border-slate-200 rounded-b-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all font-medium text-slate-700 text-sm"
                    size={5}
                  >
                    <option value="" disabled className="text-slate-400">Select from results...</option>
                    {filteredRequestStudents.length === 0 ? (
                      <option disabled>No students found</option>
                    ) : (
                      filteredRequestStudents.map(s => (
                        <option key={s.id} value={s.id}>{s.id} - {s.name}</option>
                      ))
                    )}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5">Request Type</label>
                  <div className="flex flex-col gap-2">
                    {(['Section Change', 'English Shift'] as const).map(type => (
                      <button
                        key={type}
                        type="button"
                        onClick={() => setRequestType(type)}
                        className={`p-3 text-sm font-bold rounded-xl border text-left transition-all ${
                          requestType === type 
                            ? 'bg-sky-600 border-sky-600 text-white shadow-md shadow-sky-100' 
                            : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                        }`}
                      >
                        {type}
                      </button>
                    ))}
                  </div>
                </div>

                {isPrepSectionChange && (
                  <div className="space-y-4 p-4 bg-sky-50 rounded-xl border border-sky-100 animate-in fade-in slide-in-from-top-2">
                    <div className="flex items-center gap-2 text-sky-700 font-bold text-xs uppercase mb-1">
                      <Info size={14} />
                      Prep Details Required
                    </div>
                    <div className="space-y-3">
                      <div>
                        <label className="block text-[10px] font-black text-sky-600 uppercase mb-1">Course Name</label>
                        <div className="relative">
                          <Book className="absolute left-3 top-1/2 -translate-y-1/2 text-sky-400" size={14} />
                          <select
                            value={courseName}
                            onChange={(e) => setCourseName(e.target.value)}
                            className="w-full pl-9 pr-3 py-2 bg-white border border-sky-200 rounded-lg text-sm font-semibold text-slate-500 focus:ring-2 focus:ring-sky-400 outline-none"
                          >
                            <option value="">Select Course...</option>
                            {COURSE_LIST.map(course => (
                              <option key={course} value={course}>{course}</option>
                            ))}
                          </select>
                        </div>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-sky-600 uppercase mb-1">Target Section</label>
                        <div className="relative">
                          <Hash className="absolute left-3 top-1/2 -translate-y-1/2 text-sky-400" size={14} />
                          <input
                            type="text"
                            placeholder="e.g. 104"
                            value={sectionNumber}
                            onChange={(e) => setSectionNumber(e.target.value)}
                            className="w-full pl-9 pr-3 py-2 bg-white border border-sky-200 rounded-lg text-sm font-semibold text-slate-500 focus:ring-2 focus:ring-sky-400 outline-none"
                          />
                        </div>
                      </div>
                    </div>
                  </div>
                )}

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5">Specific Justification <span className="text-slate-400 font-normal">(Optional)</span></label>
                  <textarea
                    value={requestDetails}
                    onChange={(e) => setRequestDetails(e.target.value)}
                    placeholder="Provide additional details or reasons..."
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all h-24 resize-none text-slate-500 font-medium"
                  />
                </div>

                <button
                  type="submit"
                  disabled={isSubmitDisabled}
                  className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-slate-200 flex items-center justify-center gap-2"
                >
                  <Send size={18} />
                  Send to Registrar
                </button>
              </form>
            </div>
          </div>

          <div className="lg:col-span-2 space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
               <div className="flex items-center justify-between mb-8">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-100 text-slate-600 rounded-lg"><LayoutList size={24} /></div>
                    <h2 className="text-xl font-bold text-slate-900">Recent History</h2>
                  </div>
               </div>

               <div className="space-y-4">
                 {requests.length === 0 ? (
                   <div className="text-center py-20 bg-slate-50 rounded-2xl border border-dashed border-slate-200 text-slate-400">
                      <LayoutList size={40} className="mx-auto mb-4 opacity-20" />
                      <p className="font-medium">No adjustment requests submitted yet</p>
                   </div>
                 ) : (
                   requests.map((request) => (
                     <div key={request.id} className="bg-slate-50 rounded-2xl p-6 border border-slate-200 hover:bg-white hover:shadow-md transition-all">
                        <div className="flex justify-between items-start mb-4">
                           <div className="flex items-center gap-2">
                              <span className={`px-2.5 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                                request.status === 'Processed' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                              }`}>
                                {request.status === 'Processed' ? 'FINISHED' : 'PENDING REGISTRAR'}
                              </span>
                              <span className="text-[10px] font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-100">
                                #{request.id}
                              </span>
                           </div>
                           <span className="text-xs font-medium text-slate-400">
                             {new Date(request.createdAt).toLocaleDateString()} at {new Date(request.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                           </span>
                        </div>

                        <div className="mb-3">
                          <h4 className="font-black text-slate-900">{request.studentName} <span className="text-slate-400 text-sm font-normal">({request.studentId})</span></h4>
                          <span className="text-[11px] font-bold text-sky-600 bg-sky-50 px-2 py-0.5 rounded border border-sky-100 inline-block mt-1">
                            {request.requestType}
                          </span>
                        </div>

                        <p className="text-sm text-slate-600 leading-relaxed bg-white/50 p-3 rounded-xl border border-slate-100 italic">
                          "{request.details}"
                        </p>

                        {request.status === 'Processed' && (
                          <div className="mt-4 flex items-center gap-2 text-xs font-bold text-emerald-600">
                             <CheckCircle2 size={16} />
                             Registrar has completed this adjustment
                          </div>
                        )}
                     </div>
                   ))
                 )}
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PrepDashboard;

import React, { useState, useMemo } from 'react';
import { Student, AcademicLevel, RegistrationStatus, ScheduleRequest, ActivityLog } from '../types';
import { FileUp, Send, CheckCircle2, History, Info, LayoutList, MessageSquarePlus, Download, Search, Hash, Book } from 'lucide-react';
import * as XLSX from 'xlsx';

interface PrepDashboardProps {
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  requests: ScheduleRequest[];
  setRequests: React.Dispatch<React.SetStateAction<ScheduleRequest[]>>;
  addLog: (type: ActivityLog['type'], description: string, actor: string, studentId?: string, studentName?: string) => void;
}

const COURSE_LIST = [
  'ENGL001', 'ENGL002', 'ENGL005', 
  'MATH001', 'MATH012', 
  'PYP 001', 'PYP 002', 
  'Modular Courses', 
  'PE 001', 'PE 002'
];

const PrepDashboard: React.FC<PrepDashboardProps> = ({ students, setStudents, requests, setRequests, addLog }) => {
  const [activeTab, setActiveTab] = useState<'placement' | 'adjustments'>('placement');
  const [selectedStudentId, setSelectedStudentId] = useState('');
  const [requestType, setRequestType] = useState<'Section Change' | 'English Shift'>('Section Change');
  const [requestDetails, setRequestDetails] = useState('');

  const [sectionNumber, setSectionNumber] = useState('');
  const [courseName, setCourseName] = useState('');

  const [statusSearch, setStatusSearch] = useState('');
  const [requestSearch, setRequestSearch] = useState('');

  const selectedStudent = useMemo(() => 
    students.find(s => s.id === selectedStudentId), 
    [students, selectedStudentId]
  );

  const isPrepSectionChange = selectedStudent?.academicLevel === AcademicLevel.PREP && requestType === 'Section Change';

  const handlePlacementUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        setStudents(prev => {
          const updatedStudents = [...prev];
          let updateCount = 0;
          let newCount = 0;

          data.forEach((row: any) => {
            const rowId = String(row.ID || row.id || '');
            if (!rowId) return;

            const eng = String(row.English || row.english || 'ENGL001');
            const math = String(row.Math || row.math || 'MATH001');

            const engSec = row['English Section'] || row.english_section ? String(row['English Section'] || row.english_section) : undefined;
            const mathSec = row['Math Section'] || row.math_section ? String(row['Math Section'] || row.math_section) : undefined;

            const isPromoted = eng.toLowerCase() === 'promoted' && math.toLowerCase() === 'promoted';
            const level = isPromoted ? AcademicLevel.FRESHMAN : AcademicLevel.PREP;

            const existingIndex = updatedStudents.findIndex(s => s.id === rowId);

            const detailString = `English: ${eng} (Sec: ${engSec || 'N/A'}) | Math: ${math} (Sec: ${mathSec || 'N/A'})`;

            if (existingIndex !== -1) {
              updatedStudents[existingIndex] = {
                ...updatedStudents[existingIndex],
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec || updatedStudents[existingIndex].englishSection,
                mathSection: mathSec || updatedStudents[existingIndex].mathSection,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              };
              updateCount++;
              addLog('Placement', `Updated Data: ${detailString}. Status reset to Under Process.`, 'Prep Dept', rowId, updatedStudents[existingIndex].name);
            } else {
              const newName = String(row.Name || row.name || 'External Record');
              updatedStudents.push({
                id: rowId,
                name: newName,
                gender: 'Male',
                admittedMajor: 'Not Provided',
                term: '241',
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec,
                mathSection: mathSec,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              });
              newCount++;
              addLog('Placement', `New Record: ${detailString}. Status: Under Process.`, 'Prep Dept', rowId, newName);
            }
          });

          alert(`Placement update complete: ${updateCount} students updated, ${newCount} new records created. All updated records reset to Under Process.`);
          return updatedStudents;
        });

      } catch (err) {
        console.error(err);
        alert("Error parsing file. Ensure columns include ID, English, Math, 'English Section', and 'Math Section'.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const downloadPlacementTemplate = () => {
    const templateData = [
      { ID: '20241001', English: 'Promoted', Math: 'MATH001', 'English Section': '45', 'Math Section': '55' },
      { ID: '20241002', English: 'ENGL001', Math: 'Promoted', 'English Section': '10', 'Math Section': '20' }
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Placements");
    XLSX.writeFile(wb, "Student_Placement_Template.xlsx");
  };

  const handleSubmitRequest = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStudent) {
      alert("Student ID not found.");
      return;
    }

    let finalDetails = requestDetails;
    if (isPrepSectionChange) {
      finalDetails = `[COURSE: ${courseName} | NEW SECTION: ${sectionNumber}]${requestDetails ? ' - ' + requestDetails : ''}`;
    }

    const newRequest: ScheduleRequest = {
      id: Math.random().toString(36).substr(2, 9),
      studentId: selectedStudent.id,
      studentName: selectedStudent.name,
      requestType,
      details: finalDetails || 'No justification provided.',
      courseName: isPrepSectionChange ? courseName : undefined,
      sectionNumber: isPrepSectionChange ? sectionNumber : undefined,
      status: 'Pending',
      createdAt: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    addLog('Adjustment', `Submitted ${requestType}: ${finalDetails || 'Request sent.'}`, 'Prep Dept', selectedStudent.id, selectedStudent.name);

    setRequestDetails('');
    setSectionNumber('');
    setCourseName('');
    setSelectedStudentId('');
    setRequestSearch('');
    alert("Schedule adjustment request sent to Registrar.");
  };

  const filteredStatusStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(statusSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(statusSearch.toLowerCase())
    );
  }, [students, statusSearch]);

  const filteredRequestStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(requestSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(requestSearch.toLowerCase())
    );
  }, [students, requestSearch]);

  const isSubmitDisabled = !selectedStudentId || (isPrepSectionChange && (!sectionNumber || !courseName));

  return (
    <div className="space-y-6">
      <div className="flex gap-4 border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('placement')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'placement' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <FileUp size={18} />
          Placement Control
        </button>
        <button 
          onClick={() => setActiveTab('adjustments')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'adjustments' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <MessageSquarePlus size={18} />
          Schedule Adjustments
        </button>
      </div>

      {activeTab === 'placement' ? (
        <div className="grid grid-cols-1 gap-8">
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-sky-100 text-sky-600 rounded-lg"><FileUp size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">Placement Processing</h2>
                  <p className="text-sm text-slate-500">Update existing students with test results</p>
                </div>
              </div>
              <button 
                onClick={downloadPlacementTemplate}
                className="flex items-center gap-2 text-xs font-bold text-sky-600 bg-sky-50 px-3 py-2 rounded-lg hover:bg-sky-100 transition-colors"
              >
                <Download size={14} />
                Download Placement Template
              </button>
            </div>

            <div className="grid grid-cols-1 gap-8">
              <div className="border-2 border-dashed border-slate-200 rounded-2xl p-10 text-center space-y-4 hover:border-sky-300 transition-colors bg-slate-50/30 group">
                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto text-slate-400 shadow-sm border border-slate-100 group-hover:scale-110 transition-transform">
                  <FileUp size={32} className="group-hover:text-sky-500" />
                </div>
                <div>
                  <p className="font-semibold text-slate-700">Drop Placement Excel here</p>
                  <p className="text-sm text-slate-400">Include 'English Section' and 'Math Section' columns</p>
                </div>
                <label className="inline-block px-6 py-3 bg-slate-900 text-white rounded-xl cursor-pointer hover:bg-slate-800 transition-all font-medium shadow-lg shadow-slate-200">
                  Import Test Results
                  <input type="file" className="hidden" onChange={handlePlacementUpload} accept=".xlsx, .xls, .csv" />
                </label>
              </div>
            </div>
          </div>

          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
             <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><History size={24} /></div>
                  <h2 className="text-xl font-bold text-slate-900">Live Status Monitor</h2>
                </div>
                <div className="relative w-full md:w-72">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <input
                    type="text"
                    placeholder="Search student by Name or ID..."
                    value={statusSearch}
                    onChange={(e) => setStatusSearch(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-sm font-medium text-slate-500"
                  />
                </div>
             </div>

             <div className="overflow-x-auto rounded-xl border border-slate-100">
               <table className="w-full text-left">
                 <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                   <tr>
                     <th className="px-6 py-4">Student</th>
                     <th className="px-6 py-4">Placement</th>
                     <th className="px-6 py-4">Section Number</th>
                     <th className="px-6 py-4">Academic Level</th>
                     <th className="px-6 py-4 text-center">Status</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                   {filteredStatusStudents.length === 0 ? (
                     <tr>
                       <td colSpan={5} className="px-6 py-12 text-center text-slate-400 font-medium">
                         No students found matching your search.
                       </td>
                     </tr>
                   ) : (
                     filteredStatusStudents.map(s => (
                       <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                         <td className="px-6 py-4">
                            <div className="font-bold text-slate-900">{s.name}</div>
                            <div className="text-xs text-slate-400 font-mono font-bold uppercase">{s.id}</div>
                         </td>
                         <td className="px-6 py-4">
                            <div className="flex gap-2">
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">E: {s.englishPlacement}</span>
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">M: {s.mathPlacement}</span>
                            </div>
                         </td>
                         <td className="px-6 py-4">
                           <span className="text-sm font-mono font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">
                             E:{s.englishSection || '-'} M:{s.mathSection || '-'}
                           </span>
                         </td>
                         <td className="px-6 py-4">
                           <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${s.academicLevel === 'Prep' ? 'bg-indigo-100 text-indigo-700' : 'bg-emerald-100 text-emerald-700'}`}>
                              {s.academicLevel}
                           </span>
                         </td>
                         <td className="px-6 py-4 text-center">
                            <span className={`inline-flex items-center gap-1.5 text-xs font-bold ${s.status === RegistrationStatus.REGISTERED ? 'text-emerald-600' : 'text-amber-600'}`}>
                               {s.status === RegistrationStatus.REGISTERED ? <CheckCircle2 size={14} /> : <div className="w-3.5 h-3.5 border-2 border-amber-600 border-t-transparent rounded-full animate-spin"></div>}
                               {s.status}
                            </span>
                         </td>
                       </tr>
                     ))
                   )}
                 </tbody>
               </table>
             </div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 sticky top-24">
              <div className="flex items-center gap-3 mb-6">
                <div className="p-2 bg-amber-100 text-amber-600 rounded-lg"><Send size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">New Request</h2>
                  <p className="text-sm text-slate-500">Submit adjustment to Registrar</p>
                </div>
              </div>

              <form onSubmit={handleSubmitRequest} className="space-y-5">
                <div className="space-y-2">
                  <label className="block text-sm font-bold text-slate-700">Target Student</label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                    <input
                      type="text"
                      placeholder="Type name or ID to filter..."
                      value={requestSearch}
                      onChange={(e) => setRequestSearch(e.target.value)}
                      className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-t-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-xs font-medium text-slate-500"
                    />
                  </div>
                  <select 
                    value={selectedStudentId}
                    onChange={(e) => setSelectedStudentId(e.target.value)}
                    className="w-full p-3 bg-white border border-t-0 border-slate-200 rounded-b-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all font-medium text-slate-700 text-sm"
                    size={5}
                  >
                    <option value="" disabled className="text-slate-400">Select from results...</option>
                    {filteredRequestStudents.length === 0 ? (
                      <option disabled>No students found</option>
                    ) : (
                      filteredRequestStudents.map(s => (
                        <option key={s.id} value={s.id}>{s.id} - {s.name}</option>
                      ))
                    )}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5">Request Type</label>
                  <div className="flex flex-col gap-2">
                    {(['Section Change', 'English Shift'] as const).map(type => (
                      <button
                        key={type}
                        type="button"
                        onClick={() => setRequestType(type)}
                        className={`p-3 text-sm font-bold rounded-xl border text-left transition-all ${
                          requestType === type 
                            ? 'bg-sky-600 border-sky-600 text-white shadow-md shadow-sky-100' 
                            : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                        }`}
                      >
                        {type}
                      </button>
                    ))}
                  </div>
                </div>

                {isPrepSectionChange && (
                  <div className="space-y-4 p-4 bg-sky-50 rounded-xl border border-sky-100 animate-in fade-in slide-in-from-top-2">
                    <div className="flex items-center gap-2 text-sky-700 font-bold text-xs uppercase mb-1">
                      <Info size={14} />
                      Prep Details Required
                    </div>
                    <div className="space-y-3">
                      <div>
                        <label className="block text-[10px] font-black text-sky-600 uppercase mb-1">Course Name</label>
                        <div className="relative">
                          <Book className="absolute left-3 top-1/2 -translate-y-1/2 text-sky-400" size={14} />
                          <select
                            value={courseName}
                            onChange={(e) => setCourseName(e.target.value)}
                            className="w-full pl-9 pr-3 py-2 bg-white border border-sky-200 rounded-lg text-sm font-semibold text-slate-500 focus:ring-2 focus:ring-sky-400 outline-none"
                          >
                            <option value="">Select Course...</option>
                            {COURSE_LIST.map(course => (
                              <option key={course} value={course}>{course}</option>
                            ))}
                          </select>
                        </div>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-sky-600 uppercase mb-1">Target Section</label>
                        <div className="relative">
                          <Hash className="absolute left-3 top-1/2 -translate-y-1/2 text-sky-400" size={14} />
                          <input
                            type="text"
                            placeholder="e.g. 104"
                            value={sectionNumber}
                            onChange={(e) => setSectionNumber(e.target.value)}
                            className="w-full pl-9 pr-3 py-2 bg-white border border-sky-200 rounded-lg text-sm font-semibold text-slate-500 focus:ring-2 focus:ring-sky-400 outline-none"
                          />
                        </div>
                      </div>
                    </div>
                  </div>
                )}

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5">Specific Justification <span className="text-slate-400 font-normal">(Optional)</span></label>
                  <textarea
                    value={requestDetails}
                    onChange={(e) => setRequestDetails(e.target.value)}
                    placeholder="Provide additional details or reasons..."
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all h-24 resize-none text-slate-500 font-medium"
                  />
                </div>

                <button
                  type="submit"
                  disabled={isSubmitDisabled}
                  className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-slate-200 flex items-center justify-center gap-2"
                >
                  <Send size={18} />
                  Send to Registrar
                </button>
              </form>
            </div>
          </div>

          <div className="lg:col-span-2 space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
               <div className="flex items-center justify-between mb-8">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-100 text-slate-600 rounded-lg"><LayoutList size={24} /></div>
                    <h2 className="text-xl font-bold text-slate-900">Recent History</h2>
                  </div>
               </div>

               <div className="space-y-4">
                 {requests.length === 0 ? (
                   <div className="text-center py-20 bg-slate-50 rounded-2xl border border-dashed border-slate-200 text-slate-400">
                      <LayoutList size={40} className="mx-auto mb-4 opacity-20" />
                      <p className="font-medium">No adjustment requests submitted yet</p>
                   </div>
                 ) : (
                   requests.map((request) => (
                     <div key={request.id} className="bg-slate-50 rounded-2xl p-6 border border-slate-200 hover:bg-white hover:shadow-md transition-all">
                        <div className="flex justify-between items-start mb-4">
                           <div className="flex items-center gap-2">
                              <span className={`px-2.5 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                                request.status === 'Processed' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                              }`}>
                                {request.status === 'Processed' ? 'FINISHED' : 'PENDING REGISTRAR'}
                              </span>
                              <span className="text-[10px] font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-100">
                                #{request.id}
                              </span>
                           </div>
                           <span className="text-xs font-medium text-slate-400">
                             {new Date(request.createdAt).toLocaleDateString()} at {new Date(request.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                           </span>
                        </div>

                        <div className="mb-3">
                          <h4 className="font-black text-slate-900">{request.studentName} <span className="text-slate-400 text-sm font-normal">({request.studentId})</span></h4>
                          <span className="text-[11px] font-bold text-sky-600 bg-sky-50 px-2 py-0.5 rounded border border-sky-100 inline-block mt-1">
                            {request.requestType}
                          </span>
                        </div>

                        <p className="text-sm text-slate-600 leading-relaxed bg-white/50 p-3 rounded-xl border border-slate-100 italic">
                          "{request.details}"
                        </p>

                        {request.status === 'Processed' && (
                          <div className="mt-4 flex items-center gap-2 text-xs font-bold text-emerald-600">
                             <CheckCircle2 size={16} />
                             Registrar has completed this adjustment
                          </div>
                        )}
                     </div>
                   ))
                 )}
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PrepDashboard;

import React, { useState, useMemo } from 'react';
import { Student, RegistrationStatus, ScheduleRequest, AcademicLevel, ActivityLog } from '../types';
import { FileUp, Download, CheckCircle2, Clock, AlertCircle, Users, CheckSquare, Square, CheckCircle, Filter, FileSpreadsheet, History, Search, UserCheck, FileText, Calendar } from 'lucide-react';
import * as XLSX from 'xlsx';

interface RegistrarDashboardProps {
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  requests: ScheduleRequest[];
  setRequests: React.Dispatch<React.SetStateAction<ScheduleRequest[]>>;
  logs: ActivityLog[];
  addLog: (type: ActivityLog['type'], description: string, actor: string, studentId?: string, studentName?: string) => void;
}

const RegistrarDashboard: React.FC<RegistrarDashboardProps> = ({ students, setStudents, requests, setRequests, logs, addLog }) => {
  const [activeTab, setActiveTab] = useState<'students' | 'requests' | 'history'>('students');
  const [selectedTerm, setSelectedTerm] = useState<string>('All');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [selectedRequestIds, setSelectedRequestIds] = useState<string[]>([]);
  const [logSearch, setLogSearch] = useState('');

  const uniqueTerms = useMemo(() => {
    const terms = Array.from(new Set(students.map(s => s.term))).sort().reverse();
    return ['All', ...terms];
  }, [students]);

  const filteredStudents = useMemo(() => {
    if (selectedTerm === 'All') return students;
    return students.filter(s => s.term === selectedTerm);
  }, [students, selectedTerm]);

  const filteredLogs = useMemo(() => {
    if (!logSearch) return logs;
    const search = logSearch.toLowerCase();
    return logs.filter(l => 
      l.description.toLowerCase().includes(search) || 
      l.type.toLowerCase().includes(search) ||
      l.studentId?.toLowerCase().includes(search) ||
      l.studentName?.toLowerCase().includes(search)
    );
  }, [logs, logSearch]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        const newStudents: Student[] = data.map((row: any) => ({
          id: String(row.ID || row.id || ''),
          name: String(row.Name || row.name || 'Unknown Student'),
          gender: (row.Gender || row.gender || 'Male') as 'Male' | 'Female',
          admittedMajor: String(row.Major || row.major || 'Undecided'),
          term: String(row.Term || row.term || '261'),
          englishPlacement: 'Pending',
          mathPlacement: 'Pending',
          academicLevel: AcademicLevel.PREP,
          status: RegistrationStatus.UNDER_PROCESS,
          updatedAt: new Date().toISOString(),
          englishSection: row['English Section'] || row.english_section ? String(row['English Section'] || row.english_section) : undefined,
          mathSection: row['Math Section'] || row.math_section ? String(row['Math Section'] || row.math_section) : undefined
        })).filter(s => s.id !== '');

        setStudents(prev => {
          const existingIds = new Set(prev.map(s => s.id));
          const filteredNew = newStudents.filter(s => !existingIds.has(s.id));
          addLog('Admission', `Imported ${filteredNew.length} new student records from Excel.`, 'Registrar');
          return [...prev, ...filteredNew];
        });

        alert(`Successfully imported ${newStudents.length} base student records.`);
      } catch (err) {
        alert("Error importing data. Please ensure the Excel file matches the template headers.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const downloadInitialTemplate = () => {
    const templateData = [
      { ID: '20241001', Name: 'Ahmed Al-Fulan', Gender: 'Male', Major: 'Mechanical Engineering', Term: '261' },
      { ID: '20241002', Name: 'Sara Al-Fulan', Gender: 'Female', Major: 'Computer Science', Term: '261' },
      { ID: '20241003', Name: 'Khalid Abdullah', Gender: 'Male', Major: 'Industrial Design', Term: '262' }
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Admissions_Template");
    XLSX.writeFile(wb, "Initial_Students_Template.xlsx");
  };

  const updateStatus = (id: string, newStatus: RegistrationStatus) => {
    const student = students.find(s => s.id === id);
    if (student) {
      addLog('StatusUpdate', `Status changed to ${newStatus}.`, 'Registrar', student.id, student.name);
    }
    setStudents(prev => prev.map(s => s.id === id ? { ...s, status: newStatus, updatedAt: new Date().toISOString() } : s));
  };

  const handleBulkStatusUpdate = (newStatus: RegistrationStatus) => {
    selectedIds.forEach(id => {
      const student = students.find(s => s.id === id);
      if (student) {
        addLog('StatusUpdate', `Bulk update: status set to ${newStatus}.`, 'Registrar', student.id, student.name);
      }
    });
    setStudents(prev => prev.map(s => 
      selectedIds.includes(s.id) ? { ...s, status: newStatus, updatedAt: new Date().toISOString() } : s
    ));
    setSelectedIds([]);
  };

  const handleBulkRequestProcess = () => {
    selectedRequestIds.forEach(id => {
      const req = requests.find(r => r.id === id);
      if (req) {
        addLog('Adjustment', `Bulk update: Finished processing ${req.requestType}.`, 'Registrar', req.studentId, req.studentName);
      }
    });
    setRequests(prev => prev.map(r => 
      selectedRequestIds.includes(r.id) ? { ...r, status: 'Processed' as const } : r
    ));
    setSelectedRequestIds([]);
  };

  const toggleSelectAll = () => {
    if (activeTab === 'students') {
      if (selectedIds.length === filteredStudents.length) {
        setSelectedIds([]);
      } else {
        setSelectedIds(filteredStudents.map(s => s.id));
      }
    } else if (activeTab === 'requests') {
      const pendingRequests = requests.filter(r => r.status === 'Pending');
      if (selectedRequestIds.length === pendingRequests.length) {
        setSelectedRequestIds([]);
      } else {
        setSelectedRequestIds(pendingRequests.map(r => r.id));
      }
    }
  };

  const toggleSelectOne = (id: string) => {
    if (activeTab === 'students') {
      setSelectedIds(prev => 
        prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
      );
    } else {
      setSelectedRequestIds(prev => 
        prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
      );
    }
  };

  const processRequest = (requestId: string) => {
    const req = requests.find(r => r.id === requestId);
    if (req) {
      addLog('Adjustment', `Finished processing ${req.requestType}.`, 'Registrar', req.studentId, req.studentName);
    }
    setRequests(prev => prev.map(r => r.id === requestId ? { ...r, status: 'Processed' as const } : r));
  };

  const downloadData = () => {
    const exportData = students.map(s => ({
      'Student ID': s.id,
      'Name': s.name,
      'Gender': s.gender,
      'Major': s.admittedMajor,
      'Term': s.term,
      'English Section': s.englishSection || 'N/A',
      'Math Section': s.mathSection || 'N/A',
      'English Placement': s.englishPlacement,
      'Math Placement': s.mathPlacement,
      'Academic Level': s.academicLevel,
      'Registration Status': s.status,
      'Last Updated': new Date(s.updatedAt).toLocaleString()
    }));

    const worksheet = XLSX.utils.json_to_sheet(exportData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, 'Students');
    XLSX.writeFile(workbook, `Banner_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const downloadRequestsData = () => {
    const exportData = requests.map(r => ({
      'Request ID': r.id,
      'Student ID': r.studentId,
      'Student Name': r.studentName,
      'Request Type': r.requestType,
      'Course': r.courseName || 'N/A',
      'Section Number': r.sectionNumber || 'N/A',
      'Adjustment Details': r.details,
      'Status': r.status,
      'Submitted Date': new Date(r.createdAt).toLocaleString()
    }));

    const worksheet = XLSX.utils.json_to_sheet(exportData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, 'Adjustment Requests');
    XLSX.writeFile(workbook, `Adjustment_Requests_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const stats = {
    total: students.length,
    registered: students.filter(s => s.status === RegistrationStatus.REGISTERED).length,
    pending: students.filter(s => s.status === RegistrationStatus.UNDER_PROCESS).length,
    requests: requests.filter(r => r.status === 'Pending').length,
  };

  const anySelected = activeTab === 'students' ? selectedIds.length > 0 : (activeTab === 'requests' ? selectedRequestIds.length > 0 : false);

  return (
    <div className="space-y-8 relative pb-20">
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-sky-100 text-sky-600 rounded-lg"><Users size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Total Students</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.total}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-emerald-100 text-emerald-600 rounded-lg"><CheckCircle2 size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Registered</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.registered}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-amber-100 text-amber-600 rounded-lg"><Clock size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Under Process</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.pending}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-red-100 text-red-600 rounded-lg"><AlertCircle size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Open Requests</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.requests}</div>
        </div>
      </div>

      <div className="flex items-center justify-between border-b border-slate-200 pb-4">
        <div className="flex gap-8">
          <button 
            onClick={() => setActiveTab('students')}
            className={`pb-4 px-2 font-medium transition-all ${activeTab === 'students' ? 'text-sky-600 border-b-2 border-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Student Master List
          </button>
          <button 
            onClick={() => setActiveTab('requests')}
            className={`pb-4 px-2 font-medium transition-all ${activeTab === 'requests' ? 'text-sky-600 border-b-2 border-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Schedule Adjustments
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`pb-4 px-2 font-medium transition-all ${activeTab === 'history' ? 'text-sky-600 border-b-2 border-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <div className="flex items-center gap-2">
              <History size={16} />
              History Log
            </div>
          </button>
        </div>
        <div className="flex items-center gap-3">
          {activeTab === 'students' && (
            <>
              <button 
                onClick={downloadInitialTemplate}
                className="text-xs font-bold text-slate-500 hover:text-slate-700 underline underline-offset-4"
              >
                Downloads template
              </button>
              <label className="flex items-center gap-2 px-4 py-2 bg-sky-600 text-white rounded-lg hover:bg-sky-700 cursor-pointer transition-colors text-sm font-medium shadow-sm">
                <FileUp size={16} />
                Import Admissions
                <input type="file" className="hidden" onChange={handleFileUpload} accept=".xlsx, .xls, .csv" />
              </label>
              <button 
                onClick={downloadData}
                className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium shadow-sm"
              >
                <Download size={16} />
                Export for Banner
              </button>
            </>
          )}
          {activeTab === 'requests' && (
            <button 
              onClick={downloadRequestsData}
              className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium shadow-sm"
            >
              <FileSpreadsheet size={16} />
              Export Requests
            </button>
          )}
        </div>
      </div>

      {activeTab === 'students' && (
        <>
          <div className="flex items-center gap-4 mb-2 overflow-x-auto pb-2 scrollbar-hide">
            <div className="flex items-center gap-2 text-slate-400 mr-2 shrink-0">
              <Filter size={16} />
              <span className="text-xs font-bold uppercase tracking-wider">Filter by Term:</span>
            </div>
            <div className="flex gap-2">
              {uniqueTerms.map((term) => (
                <button
                  key={term}
                  onClick={() => {
                    setSelectedTerm(term);
                    setSelectedIds([]);
                  }}
                  className={`px-4 py-2 rounded-xl text-sm font-bold transition-all border ${
                    selectedTerm === term 
                      ? 'bg-sky-600 border-sky-600 text-white shadow-md shadow-sky-100' 
                      : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                  }`}
                >
                  {term === 'All' ? 'All Terms' : `Term ${term}`}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 text-slate-500 text-sm font-medium">
                <tr>
                  <th className="px-6 py-4 w-12">
                    <button 
                      onClick={toggleSelectAll}
                      className={`transition-colors ${selectedIds.length === filteredStudents.length && filteredStudents.length > 0 ? 'text-sky-600' : 'text-slate-300 hover:text-slate-400'}`}
                    >
                      {selectedIds.length === filteredStudents.length && filteredStudents.length > 0 ? <CheckSquare size={20} /> : <Square size={20} />}
                    </button>
                  </th>
                  <th className="px-6 py-4">Student ID</th>
                  <th className="px-6 py-4">Name</th>
                  <th className="px-6 py-4">Term</th>
                  <th className="px-6 py-4">Section Number</th>
                  <th className="px-6 py-4">Academic Level</th>
                  <th className="px-6 py-4">Placements (E/M)</th>
                  <th className="px-6 py-4 text-center">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 text-slate-700">
                {filteredStudents.map((student) => (
                  <tr 
                    key={student.id} 
                    className={`transition-colors ${selectedIds.includes(student.id) ? 'bg-sky-50/50' : 'hover:bg-slate-50'}`}
                  >
                    <td className="px-6 py-4">
                      <button 
                        onClick={() => toggleSelectOne(student.id)}
                        className={`transition-colors ${selectedIds.includes(student.id) ? 'text-sky-600' : 'text-slate-300 hover:text-slate-400'}`}
                      >
                        {selectedIds.includes(student.id) ? <CheckSquare size={20} /> : <Square size={20} />}
                      </button>
                    </td>
                    <td className="px-6 py-4 font-mono text-sm font-bold text-slate-900">{student.id}</td>
                    <td className="px-6 py-4">
                      <div className="font-semibold text-slate-800">{student.name}</div>
                      <div className="text-xs text-slate-400 uppercase font-bold tracking-wider">{student.admittedMajor}</div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-xs font-black text-slate-500 bg-slate-100 px-2 py-1 rounded">
                        {student.term}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-sm font-mono font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">
                        E:{student.englishSection || '-'} M:{student.mathSection || '-'}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${student.academicLevel === 'Prep' ? 'bg-indigo-100 text-indigo-700' : 'bg-emerald-100 text-emerald-700'}`}>
                        {student.academicLevel}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-[11px] font-bold">
                      <span className="text-slate-400 uppercase mr-1">E:</span> 
                      <span className={student.englishPlacement === 'Pending' ? 'text-amber-500' : 'text-slate-700'}>{student.englishPlacement}</span>
                      <br/>
                      <span className="text-slate-400 uppercase mr-1">M:</span> 
                      <span className={student.mathPlacement === 'Pending' ? 'text-amber-500' : 'text-slate-700'}>{student.mathPlacement}</span>
                    </td>
                    <td className="px-6 py-4">
                      <select
                        value={student.status}
                        onChange={(e) => updateStatus(student.id, e.target.value as RegistrationStatus)}
                        className={`w-full p-2 rounded-lg text-sm font-bold outline-none border transition-all ${
                          student.status === RegistrationStatus.REGISTERED 
                            ? 'bg-emerald-50 border-emerald-200 text-emerald-700' 
                            : 'bg-amber-50 border-amber-200 text-amber-700'
                        }`}
                      >
                        <option value={RegistrationStatus.UNDER_PROCESS}>Under Process</option>
                        <option value={RegistrationStatus.REGISTERED}>Registered</option>
                      </select>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredStudents.length === 0 && (
              <div className="p-12 text-center text-slate-400">
                No students found for this term.
              </div>
            )}
          </div>
        </>
      )}

      {activeTab === 'requests' && (
        <div className="space-y-4">
          {requests.length > 0 && (
            <div className="flex items-center gap-3 px-4 py-2 mb-2 bg-slate-50 rounded-xl border border-slate-200 w-fit">
              <button 
                onClick={toggleSelectAll}
                className={`flex items-center gap-2 text-sm font-bold transition-colors ${selectedRequestIds.length === requests.filter(r => r.status === 'Pending').length ? 'text-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
              >
                {selectedRequestIds.length === requests.filter(r => r.status === 'Pending').length ? <CheckSquare size={18} /> : <Square size={18} />}
                Select All Pending
              </button>
            </div>
          )}

          <div className="grid gap-4">
            {requests.length === 0 ? (
              <div className="bg-white p-12 text-center text-slate-400 rounded-2xl border border-slate-200 border-dashed">
                No pending schedule adjustment requests.
              </div>
            ) : (
              requests.map((request) => (
                <div 
                  key={request.id} 
                  className={`bg-white p-6 rounded-2xl shadow-sm border transition-all flex items-center gap-6 ${selectedRequestIds.includes(request.id) ? 'border-sky-300 bg-sky-50/30' : 'border-slate-200'}`}
                >
                  {request.status === 'Pending' && (
                    <button 
                      onClick={() => toggleSelectOne(request.id)}
                      className={`transition-colors shrink-0 ${selectedRequestIds.includes(request.id) ? 'text-sky-600' : 'text-slate-300 hover:text-slate-400'}`}
                    >
                      {selectedRequestIds.includes(request.id) ? <CheckSquare size={24} /> : <Square size={24} />}
                    </button>
                  )}

                  <div className="flex-1">
                    <div className="flex items-center gap-3 mb-1">
                      <span className={`text-[10px] font-black uppercase tracking-[0.1em] px-2 py-0.5 rounded ${
                        request.requestType === 'Section Change' ? 'bg-sky-100 text-sky-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {request.requestType}
                      </span>
                      <span className="text-xs text-slate-400 font-medium">Submitted {new Date(request.createdAt).toLocaleDateString()}</span>
                    </div>
                    <h3 className="font-bold text-slate-900">{request.studentName} <span className="text-slate-400 text-sm font-normal">({request.studentId})</span></h3>
                    <p className="text-slate-600 mt-2 text-sm leading-relaxed">{request.details}</p>
                  </div>

                  <div className="flex items-center gap-4">
                    {request.status === 'Processed' ? (
                      <span className="flex items-center gap-1.5 text-emerald-600 font-bold bg-emerald-50 px-4 py-2 rounded-xl border border-emerald-100">
                        <CheckCircle2 size={18} />
                        Finished
                      </span>
                    ) : (
                      <button 
                        onClick={() => processRequest(request.id)}
                        className="px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-xl hover:bg-slate-50 transition-colors font-bold text-sm shadow-sm"
                      >
                        Mark Finished
                      </button>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Search history by ID, Name, Action or Event Type..."
              value={logSearch}
              onChange={(e) => setLogSearch(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-white border border-slate-200 rounded-2xl shadow-sm focus:ring-2 focus:ring-sky-500 outline-none transition-all font-medium"
            />
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
              <h3 className="font-bold text-slate-900 flex items-center gap-2">
                <History size={18} className="text-sky-600" />
                Student Activity History Log
              </h3>
              <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">{filteredLogs.length} Events Total</span>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                  <tr>
                    <th className="px-6 py-4">Date & Time</th>
                    <th className="px-6 py-4">Student ID</th>
                    <th className="px-6 py-4">Student Name</th>
                    <th className="px-6 py-4">Event Type</th>
                    <th className="px-6 py-4">Action Details</th>
                    <th className="px-6 py-4">Actor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-slate-700">
                  {filteredLogs.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="p-20 text-center text-slate-400">
                        <History size={48} className="mx-auto mb-4 opacity-10" />
                        <p className="font-medium">No activity log entries found.</p>
                      </td>
                    </tr>
                  ) : (
                    filteredLogs.map((log) => (
                      <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="flex items-center gap-2 text-xs font-medium text-slate-500">
                            <Calendar size={12} className="text-slate-400" />
                            {new Date(log.timestamp).toLocaleDateString()}
                          </div>
                          <div className="flex items-center gap-2 text-[10px] text-slate-400 ml-5">
                            <Clock size={10} />
                            {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className="font-mono text-xs font-bold text-slate-900 bg-slate-100 px-2 py-1 rounded">
                            {log.studentId || 'SYSTEM'}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <div className="font-semibold text-sm text-slate-800">
                            {log.studentName || 'System Process'}
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                            log.type === 'Admission' ? 'bg-sky-100 text-sky-700' :
                            log.type === 'Placement' ? 'bg-indigo-100 text-indigo-700' :
                            log.type === 'StatusUpdate' ? 'bg-emerald-100 text-emerald-700' :
                            'bg-amber-100 text-amber-700'
                          }`}>
                            {log.type}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-sm text-slate-600 font-medium leading-relaxed max-w-md">
                            {log.description}
                          </p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-2">
                            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold ${
                              log.actor === 'Registrar' ? 'bg-slate-800 text-white' : 'bg-amber-100 text-amber-700'
                            }`}>
                              {log.actor.charAt(0)}
                            </div>
                            <span className="text-xs font-bold text-slate-600">{log.actor}</span>
                          </div>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* Bulk Action Toolbar */}
      {anySelected && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-6 z-50 border border-slate-700 animate-in fade-in slide-in-from-bottom-4">
          <div className="flex items-center gap-3 pr-6 border-r border-slate-700">
            <div className="w-8 h-8 bg-sky-500 rounded-lg flex items-center justify-center font-bold text-sm">
              {activeTab === 'students' ? selectedIds.length : selectedRequestIds.length}
            </div>
            <span className="text-sm font-semibold">{activeTab === 'students' ? 'Students' : 'Requests'} Selected</span>
          </div>
          <div className="flex items-center gap-3">
            <span className="text-xs text-slate-400 font-bold uppercase tracking-wider">Bulk Actions:</span>

            {activeTab === 'students' ? (
              <>
                <button 
                  onClick={() => handleBulkStatusUpdate(RegistrationStatus.REGISTERED)}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-500 rounded-xl text-sm font-bold transition-colors"
                >
                  <CheckCircle2 size={16} />
                  Mark Registered
                </button>
                <button 
                  onClick={() => handleBulkStatusUpdate(RegistrationStatus.UNDER_PROCESS)}
                  className="flex items-center gap-2 px-4 py-2 bg-amber-600 hover:bg-amber-500 rounded-xl text-sm font-bold transition-colors"
                >
                  <Clock size={16} />
                  Mark Under Process
                </button>
              </>
            ) : (
              <button 
                onClick={handleBulkRequestProcess}
                className="flex items-center gap-2 px-4 py-2 bg-sky-600 hover:bg-sky-500 rounded-xl text-sm font-bold transition-colors"
              >
                <CheckCircle size={16} />
                Mark all as Finished
              </button>
            )}

            <button 
              onClick={() => activeTab === 'students' ? setSelectedIds([]) : setSelectedRequestIds([])}
              className="px-4 py-2 text-slate-400 hover:text-white text-sm font-medium"
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default RegistrarDashboard;

import React, { useState, useMemo } from 'react';
import { Student, AcademicLevel, RegistrationStatus, ScheduleRequest, ActivityLog } from '../types';
import { FileUp, Send, CheckCircle2, History, Info, LayoutList, MessageSquarePlus, Download, Search, Hash, Book } from 'lucide-react';
import * as XLSX from 'xlsx';

interface PrepDashboardProps {
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  requests: ScheduleRequest[];
  setRequests: React.Dispatch<React.SetStateAction<ScheduleRequest[]>>;
  addLog: (type: ActivityLog['type'], description: string, actor: string, studentId?: string, studentName?: string) => void;
}

const COURSE_LIST = [
  'ENGL001', 'ENGL002', 'ENGL003', 'ENGL004', 'ENGL005', 
  'MATH001', 'MATH002', 'MATH012', 
  'PYP 001', 'PYP 002', 
  'Modular Courses', 
  'PE 001', 'PE 002'
];

const PrepDashboard: React.FC<PrepDashboardProps> = ({ students, setStudents, requests, setRequests, addLog }) => {
  const [activeTab, setActiveTab] = useState<'placement' | 'adjustments'>('placement');
  const [selectedStudentId, setSelectedStudentId] = useState('');
  const [requestType, setRequestType] = useState<'Section Change' | 'English Shift'>('Section Change');
  const [requestDetails, setRequestDetails] = useState('');

  const [sectionNumber, setSectionNumber] = useState('');
  const [courseName, setCourseName] = useState('');

  const [statusSearch, setStatusSearch] = useState('');
  const [requestSearch, setRequestSearch] = useState('');

  const selectedStudent = useMemo(() => 
    students.find(s => s.id === selectedStudentId), 
    [students, selectedStudentId]
  );

  const isPrepSectionChange = selectedStudent?.academicLevel === AcademicLevel.PREP && requestType === 'Section Change';

  const handlePlacementUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        setStudents(prev => {
          const updatedStudents = [...prev];
          let updateCount = 0;
          let newCount = 0;

          data.forEach((row: any) => {
            const rowId = String(row.ID || row.id || '');
            if (!rowId) return;

            const eng = String(row.English || row.english || 'ENGL001');
            const math = String(row.Math || row.math || 'MATH001');

            const engSec = row['English Section'] || row.english_section ? String(row['English Section'] || row.english_section) : undefined;
            const mathSec = row['Math Section'] || row.math_section ? String(row['Math Section'] || row.math_section) : undefined;

            const isPromoted = eng.toLowerCase() === 'promoted' && math.toLowerCase() === 'promoted';
            const level = isPromoted ? AcademicLevel.FRESHMAN : AcademicLevel.PREP;

            const existingIndex = updatedStudents.findIndex(s => s.id === rowId);

            const detailString = `English: ${eng} (Sec: ${engSec || 'N/A'}) | Math: ${math} (Sec: ${mathSec || 'N/A'})`;

            if (existingIndex !== -1) {
              updatedStudents[existingIndex] = {
                ...updatedStudents[existingIndex],
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec || updatedStudents[existingIndex].englishSection,
                mathSection: mathSec || updatedStudents[existingIndex].mathSection,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              };
              updateCount++;
              addLog('Placement', `Updated Data: ${detailString}. Status reset to Under Process.`, 'Prep Dept', rowId, updatedStudents[existingIndex].name);
            } else {
              const newName = String(row.Name || row.name || 'External Record');
              updatedStudents.push({
                id: rowId,
                name: newName,
                gender: 'Male',
                admittedMajor: 'Not Provided',
                term: '241',
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec,
                mathSection: mathSec,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              });
              newCount++;
              addLog('Placement', `New Record: ${detailString}. Status: Under Process.`, 'Prep Dept', rowId, newName);
            }
          });

          alert(`Placement update complete: ${updateCount} students updated, ${newCount} new records created. All updated records reset to Under Process.`);
          return updatedStudents;
        });

      } catch (err) {
        console.error(err);
        alert("Error parsing file. Ensure columns include ID, English, Math, 'English Section', and 'Math Section'.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const downloadPlacementTemplate = () => {
    const templateData = [
      { ID: '20241001', English: 'Promoted', Math: 'MATH001', 'English Section': '45', 'Math Section': '55' },
      { ID: '20241002', English: 'ENGL001', Math: 'Promoted', 'English Section': '10', 'Math Section': '20' }
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Placements");
    XLSX.writeFile(wb, "Student_Placement_Template.xlsx");
  };

  const handleSubmitRequest = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStudent) {
      alert("Student ID not found.");
      return;
    }

    let finalDetails = requestDetails;
    if (isPrepSectionChange) {
      finalDetails = `[COURSE: ${courseName} | NEW SECTION: ${sectionNumber}]${requestDetails ? ' - ' + requestDetails : ''}`;
    }

    const newRequest: ScheduleRequest = {
      id: Math.random().toString(36).substr(2, 9),
      studentId: selectedStudent.id,
      studentName: selectedStudent.name,
      requestType,
      details: finalDetails || 'No justification provided.',
      courseName: isPrepSectionChange ? courseName : undefined,
      sectionNumber: isPrepSectionChange ? sectionNumber : undefined,
      status: 'Pending',
      createdAt: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    addLog('Adjustment', `Submitted ${requestType}: ${finalDetails || 'Request sent.'}`, 'Prep Dept', selectedStudent.id, selectedStudent.name);

    setRequestDetails('');
    setSectionNumber('');
    setCourseName('');
    setSelectedStudentId('');
    setRequestSearch('');
    alert("Schedule adjustment request sent to Registrar.");
  };

  const filteredStatusStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(statusSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(statusSearch.toLowerCase())
    );
  }, [students, statusSearch]);

  const filteredRequestStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(requestSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(requestSearch.toLowerCase())
    );
  }, [students, requestSearch]);

  const isSubmitDisabled = !selectedStudentId || (isPrepSectionChange && (!sectionNumber || !courseName));

  return (
    <div className="space-y-6">
      <div className="flex gap-4 border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('placement')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'placement' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <FileUp size={18} />
          Placement Control
        </button>
        <button 
          onClick={() => setActiveTab('adjustments')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'adjustments' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <MessageSquarePlus size={18} />
          Schedule Adjustments
        </button>
      </div>

      {activeTab === 'placement' ? (
        <div className="grid grid-cols-1 gap-8">
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-sky-100 text-sky-600 rounded-lg"><FileUp size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">Placement Processing</h2>
                  <p className="text-sm text-slate-500">Update existing students with test results</p>
                </div>
              </div>
              <button 
                onClick={downloadPlacementTemplate}
                className="flex items-center gap-2 text-xs font-bold text-sky-600 bg-sky-50 px-3 py-2 rounded-lg hover:bg-sky-100 transition-colors"
              >
                <Download size={14} />
                Download Placement Template
              </button>
            </div>

            <div className="grid grid-cols-1 gap-8">
              <div className="border-2 border-dashed border-slate-200 rounded-2xl p-10 text-center space-y-4 hover:border-sky-300 transition-colors bg-slate-50/30 group">
                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto text-slate-400 shadow-sm border border-slate-100 group-hover:scale-110 transition-transform">
                  <FileUp size={32} className="group-hover:text-sky-500" />
                </div>
                <div>
                  <p className="font-semibold text-slate-700">Drop Placement Excel here</p>
                  <p className="text-sm text-slate-400">Include 'English Section' and 'Math Section' columns</p>
                </div>
                <label className="inline-block px-6 py-3 bg-slate-900 text-white rounded-xl cursor-pointer hover:bg-slate-800 transition-all font-medium shadow-lg shadow-slate-200">
                  Import Test Results
                  <input type="file" className="hidden" onChange={handlePlacementUpload} accept=".xlsx, .xls, .csv" />
                </label>
              </div>
            </div>
          </div>

          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
             <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><History size={24} /></div>
                  <h2 className="text-xl font-bold text-slate-900">Live Status Monitor</h2>
                </div>
                <div className="relative w-full md:w-72">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <input
                    type="text"
                    placeholder="Search student by Name or ID..."
                    value={statusSearch}
                    onChange={(e) => setStatusSearch(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-sm font-medium text-slate-500"
                  />
                </div>
             </div>

             <div className="overflow-x-auto rounded-xl border border-slate-100">
               <table className="w-full text-left">
                 <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                   <tr>
                     <th className="px-6 py-4">Student</th>
                     <th className="px-6 py-4">Placement</th>
                     <th className="px-6 py-4">Section Number</th>
                     <th className="px-6 py-4">Academic Level</th>
                     <th className="px-6 py-4 text-center">Status</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                   {filteredStatusStudents.length === 0 ? (
                     <tr>
                       <td colSpan={5} className="px-6 py-12 text-center text-slate-400 font-medium">
                         No students found matching your search.
                       </td>
                     </tr>
                   ) : (
                     filteredStatusStudents.map(s => (
                       <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                         <td className="px-6 py-4">
                            <div className="font-bold text-slate-900">{s.name}</div>
                            <div className="text-xs text-slate-400 font-mono font-bold uppercase">{s.id}</div>
                         </td>
                         <td className="px-6 py-4">
                            <div className="flex gap-2">
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">E: {s.englishPlacement}</span>
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">M: {s.mathPlacement}</span>
                            </div>
                         </td>
                         <td className="px-6 py-4">
                           <span className="text-sm font-mono font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">
                             E:{s.englishSection || '-'} M:{s.mathSection || '-'}
                           </span>
                         </td>
                         <td className="px-6 py-4">
                           <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${s.academicLevel === 'Prep' ? 'bg-indigo-100 text-indigo-700' : 'bg-emerald-100 text-emerald-700'}`}>
                              {s.academicLevel}
                           </span>
                         </td>
                         <td className="px-6 py-4 text-center">
                            <span className={`inline-flex items-center gap-1.5 text-xs font-bold ${s.status === RegistrationStatus.REGISTERED ? 'text-emerald-600' : 'text-amber-600'}`}>
                               {s.status === RegistrationStatus.REGISTERED ? <CheckCircle2 size={14} /> : <div className="w-3.5 h-3.5 border-2 border-amber-600 border-t-transparent rounded-full animate-spin"></div>}
                               {s.status}
                            </span>
                         </td>
                       </tr>
                     ))
                   )}
                 </tbody>
               </table>
             </div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 sticky top-24">
              <div className="flex items-center gap-3 mb-6">
                <div className="p-2 bg-amber-100 text-amber-600 rounded-lg"><Send size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">New Request</h2>
                  <p className="text-sm text-slate-500">Submit adjustment to Registrar</p>
                </div>
              </div>

              <form onSubmit={handleSubmitRequest} className="space-y-5">
                <div className="space-y-2">
                  <label className="block text-sm font-bold text-slate-700">Target Student</label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                    <input
                      type="text"
                      placeholder="Type name or ID to filter..."
                      value={requestSearch}
                      onChange={(e) => setRequestSearch(e.target.value)}
                      className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-t-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-xs font-medium text-slate-500"
                    />
                  </div>
                  <select 
                    value={selectedStudentId}
                    onChange={(e) => setSelectedStudentId(e.target.value)}
                    className="w-full p-3 bg-white border border-t-0 border-slate-200 rounded-b-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all font-medium text-slate-700 text-sm"
                    size={5}
                  >
                    <option value="" disabled className="text-slate-400">Select from results...</option>
                    {filteredRequestStudents.length === 0 ? (
                      <option disabled>No students found</option>
                    ) : (
                      filteredRequestStudents.map(s => (
                        <option key={s.id} value={s.id}>{s.id} - {s.name}</option>
                      ))
                    )}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5">Request Type</label>
                  <div className="flex flex-col gap-2">
                    {(['Section Change', 'English Shift'] as const).map(type => (
                      <button
                        key={type}
                        type="button"
                        onClick={() => setRequestType(type)}
                        className={`p-3 text-sm font-bold rounded-xl border text-left transition-all ${
                          requestType === type 
                            ? 'bg-sky-600 border-sky-600 text-white shadow-md shadow-sky-100' 
                            : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                        }`}
                      >
                        {type}
                      </button>
                    ))}
                  </div>
                </div>

                {isPrepSectionChange && (
                  <div className="space-y-4 p-4 bg-sky-50 rounded-xl border border-sky-100 animate-in fade-in slide-in-from-top-2">
                    <div className="flex items-center gap-2 text-sky-700 font-bold text-xs uppercase mb-1">
                      <Info size={14} />
                      Prep Details Required
                    </div>
                    <div className="space-y-3">
                      <div>
                        <label className="block text-[10px] font-black text-sky-600 uppercase mb-1">Course Name</label>
                        <div className="relative">
                          <Book className="absolute left-3 top-1/2 -translate-y-1/2 text-sky-400" size={14} />
                          <select
                            value={courseName}
                            onChange={(e) => setCourseName(e.target.value)}
                            className="w-full pl-9 pr-3 py-2 bg-white border border-sky-200 rounded-lg text-sm font-semibold text-slate-500 focus:ring-2 focus:ring-sky-400 outline-none"
                          >
                            <option value="">Select Course...</option>
                            {COURSE_LIST.map(course => (
                              <option key={course} value={course}>{course}</option>
                            ))}
                          </select>
                        </div>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-sky-600 uppercase mb-1">Target Section</label>
                        <div className="relative">
                          <Hash className="absolute left-3 top-1/2 -translate-y-1/2 text-sky-400" size={14} />
                          <input
                            type="text"
                            placeholder="e.g. 104"
                            value={sectionNumber}
                            onChange={(e) => setSectionNumber(e.target.value)}
                            className="w-full pl-9 pr-3 py-2 bg-white border border-sky-200 rounded-lg text-sm font-semibold text-slate-500 focus:ring-2 focus:ring-sky-400 outline-none"
                          />
                        </div>
                      </div>
                    </div>
                  </div>
                )}

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5">Specific Justification <span className="text-slate-400 font-normal">(Optional)</span></label>
                  <textarea
                    value={requestDetails}
                    onChange={(e) => setRequestDetails(e.target.value)}
                    placeholder="Provide additional details or reasons..."
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all h-24 resize-none text-slate-500 font-medium"
                  />
                </div>

                <button
                  type="submit"
                  disabled={isSubmitDisabled}
                  className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-slate-200 flex items-center justify-center gap-2"
                >
                  <Send size={18} />
                  Send to Registrar
                </button>
              </form>
            </div>
          </div>

          <div className="lg:col-span-2 space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
               <div className="flex items-center justify-between mb-8">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-100 text-slate-600 rounded-lg"><LayoutList size={24} /></div>
                    <h2 className="text-xl font-bold text-slate-900">Recent History</h2>
                  </div>
               </div>

               <div className="space-y-4">
                 {requests.length === 0 ? (
                   <div className="text-center py-20 bg-slate-50 rounded-2xl border border-dashed border-slate-200 text-slate-400">
                      <LayoutList size={40} className="mx-auto mb-4 opacity-20" />
                      <p className="font-medium">No adjustment requests submitted yet</p>
                   </div>
                 ) : (
                   requests.map((request) => (
                     <div key={request.id} className="bg-slate-50 rounded-2xl p-6 border border-slate-200 hover:bg-white hover:shadow-md transition-all">
                        <div className="flex justify-between items-start mb-4">
                           <div className="flex items-center gap-2">
                              <span className={`px-2.5 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                                request.status === 'Processed' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                              }`}>
                                {request.status === 'Processed' ? 'FINISHED' : 'PENDING REGISTRAR'}
                              </span>
                              <span className="text-[10px] font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-100">
                                #{request.id}
                              </span>
                           </div>
                           <span className="text-xs font-medium text-slate-400">
                             {new Date(request.createdAt).toLocaleDateString()} at {new Date(request.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                           </span>
                        </div>

                        <div className="mb-3">
                          <h4 className="font-black text-slate-900">{request.studentName} <span className="text-slate-400 text-sm font-normal">({request.studentId})</span></h4>
                          <span className="text-[11px] font-bold text-sky-600 bg-sky-50 px-2 py-0.5 rounded border border-sky-100 inline-block mt-1">
                            {request.requestType}
                          </span>
                        </div>

                        <p className="text-sm text-slate-600 leading-relaxed bg-white/50 p-3 rounded-xl border border-slate-100 italic">
                          "{request.details}"
                        </p>

                        {request.status === 'Processed' && (
                          <div className="mt-4 flex items-center gap-2 text-xs font-bold text-emerald-600">
                             <CheckCircle2 size={16} />
                             Registrar has completed this adjustment
                          </div>
                        )}
                     </div>
                   ))
                 )}
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PrepDashboard;

import React, { useState, useMemo } from 'react';
import { Student, RegistrationStatus, ScheduleRequest, AcademicLevel, ActivityLog } from '../types';
import { FileUp, Download, CheckCircle2, Clock, AlertCircle, Users, CheckSquare, Square, CheckCircle, Filter, FileSpreadsheet, History, Search, UserCheck, FileText, Calendar } from 'lucide-react';
import * as XLSX from 'xlsx';

interface RegistrarDashboardProps {
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  requests: ScheduleRequest[];
  setRequests: React.Dispatch<React.SetStateAction<ScheduleRequest[]>>;
  logs: ActivityLog[];
  addLog: (type: ActivityLog['type'], description: string, actor: string, studentId?: string, studentName?: string) => void;
}

const RegistrarDashboard: React.FC<RegistrarDashboardProps> = ({ students, setStudents, requests, setRequests, logs, addLog }) => {
  const [activeTab, setActiveTab] = useState<'students' | 'requests' | 'history'>('students');
  const [selectedTerm, setSelectedTerm] = useState<string>('All');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [selectedRequestIds, setSelectedRequestIds] = useState<string[]>([]);
  const [logSearch, setLogSearch] = useState('');

  const uniqueTerms = useMemo(() => {
    const terms = Array.from(new Set(students.map(s => s.term))).sort().reverse();
    return ['All', ...terms];
  }, [students]);

  const filteredStudents = useMemo(() => {
    if (selectedTerm === 'All') return students;
    return students.filter(s => s.term === selectedTerm);
  }, [students, selectedTerm]);

  const filteredLogs = useMemo(() => {
    if (!logSearch) return logs;
    const search = logSearch.toLowerCase();
    return logs.filter(l => 
      l.description.toLowerCase().includes(search) || 
      l.type.toLowerCase().includes(search) ||
      l.studentId?.toLowerCase().includes(search) ||
      l.studentName?.toLowerCase().includes(search)
    );
  }, [logs, logSearch]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        const newStudents: Student[] = data.map((row: any) => ({
          id: String(row.ID || row.id || ''),
          name: String(row.Name || row.name || 'Unknown Student'),
          gender: (row.Gender || row.gender || 'Male') as 'Male' | 'Female',
          admittedMajor: String(row.Major || row.major || 'Undecided'),
          term: String(row.Term || row.term || '261'),
          englishPlacement: 'Pending',
          mathPlacement: 'Pending',
          academicLevel: AcademicLevel.PREP,
          status: RegistrationStatus.UNDER_PROCESS,
          updatedAt: new Date().toISOString(),
          englishSection: row['English Section'] || row.english_section ? String(row['English Section'] || row.english_section) : undefined,
          mathSection: row['Math Section'] || row.math_section ? String(row['Math Section'] || row.math_section) : undefined
        })).filter(s => s.id !== '');

        setStudents(prev => {
          const existingIds = new Set(prev.map(s => s.id));
          const filteredNew = newStudents.filter(s => !existingIds.has(s.id));
          addLog('Admission', `Imported ${filteredNew.length} new student records from Excel.`, 'Registrar');
          return [...prev, ...filteredNew];
        });

        alert(`Successfully imported ${newStudents.length} base student records.`);
      } catch (err) {
        alert("Error importing data. Please ensure the Excel file matches the template headers.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const downloadInitialTemplate = () => {
    const templateData = [
      { ID: '20241001', Name: 'Ahmed Al-Fulan', Gender: 'Male', Major: 'Mechanical Engineering', Term: '261' },
      { ID: '20241002', Name: 'Sara Al-Fulan', Gender: 'Female', Major: 'Computer Science', Term: '261' },
      { ID: '20241003', Name: 'Khalid Abdullah', Gender: 'Male', Major: 'Industrial Design', Term: '262' }
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Admissions_Template");
    XLSX.writeFile(wb, "Initial_Students_Template.xlsx");
  };

  const updateStatus = (id: string, newStatus: RegistrationStatus) => {
    const student = students.find(s => s.id === id);
    if (student) {
      addLog('StatusUpdate', `Status changed to ${newStatus}.`, 'Registrar', student.id, student.name);
    }
    setStudents(prev => prev.map(s => s.id === id ? { ...s, status: newStatus, updatedAt: new Date().toISOString() } : s));
  };

  const handleBulkStatusUpdate = (newStatus: RegistrationStatus) => {
    selectedIds.forEach(id => {
      const student = students.find(s => s.id === id);
      if (student) {
        addLog('StatusUpdate', `Bulk update: status set to ${newStatus}.`, 'Registrar', student.id, student.name);
      }
    });
    setStudents(prev => prev.map(s => 
      selectedIds.includes(s.id) ? { ...s, status: newStatus, updatedAt: new Date().toISOString() } : s
    ));
    setSelectedIds([]);
  };

  const handleBulkRequestProcess = () => {
    selectedRequestIds.forEach(id => {
      const req = requests.find(r => r.id === id);
      if (req) {
        addLog('Adjustment', `Bulk update: Finished processing ${req.requestType}.`, 'Registrar', req.studentId, req.studentName);
      }
    });
    setRequests(prev => prev.map(r => 
      selectedRequestIds.includes(r.id) ? { ...r, status: 'Processed' as const } : r
    ));
    setSelectedRequestIds([]);
  };

  const toggleSelectAll = () => {
    if (activeTab === 'students') {
      if (selectedIds.length === filteredStudents.length) {
        setSelectedIds([]);
      } else {
        setSelectedIds(filteredStudents.map(s => s.id));
      }
    } else if (activeTab === 'requests') {
      const pendingRequests = requests.filter(r => r.status === 'Pending');
      if (selectedRequestIds.length === pendingRequests.length) {
        setSelectedRequestIds([]);
      } else {
        setSelectedRequestIds(pendingRequests.map(r => r.id));
      }
    }
  };

  const toggleSelectOne = (id: string) => {
    if (activeTab === 'students') {
      setSelectedIds(prev => 
        prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
      );
    } else {
      setSelectedRequestIds(prev => 
        prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
      );
    }
  };

  const processRequest = (requestId: string) => {
    const req = requests.find(r => r.id === requestId);
    if (req) {
      addLog('Adjustment', `Finished processing ${req.requestType}.`, 'Registrar', req.studentId, req.studentName);
    }
    setRequests(prev => prev.map(r => r.id === requestId ? { ...r, status: 'Processed' as const } : r));
  };

  const downloadData = () => {
    const exportData = students.map(s => ({
      'Student ID': s.id,
      'Name': s.name,
      'Gender': s.gender,
      'Major': s.admittedMajor,
      'Term': s.term,
      'English Section': s.englishSection || 'N/A',
      'Math Section': s.mathSection || 'N/A',
      'English Placement': s.englishPlacement,
      'Math Placement': s.mathPlacement,
      'Academic Level': s.academicLevel,
      'Registration Status': s.status,
      'Last Updated': new Date(s.updatedAt).toLocaleString()
    }));

    const worksheet = XLSX.utils.json_to_sheet(exportData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, 'Students');
    XLSX.writeFile(workbook, `Banner_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const downloadRequestsData = () => {
    const exportData = requests.map(r => ({
      'Request ID': r.id,
      'Student ID': r.studentId,
      'Student Name': r.studentName,
      'Request Type': r.requestType,
      'Course': r.courseName || 'N/A',
      'Section Number': r.sectionNumber || 'N/A',
      'Adjustment Details': r.details,
      'Status': r.status,
      'Submitted Date': new Date(r.createdAt).toLocaleString()
    }));

    const worksheet = XLSX.utils.json_to_sheet(exportData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, 'Adjustment Requests');
    XLSX.writeFile(workbook, `Adjustment_Requests_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const stats = {
    total: students.length,
    registered: students.filter(s => s.status === RegistrationStatus.REGISTERED).length,
    pending: students.filter(s => s.status === RegistrationStatus.UNDER_PROCESS).length,
    requests: requests.filter(r => r.status === 'Pending').length,
  };

  const anySelected = activeTab === 'students' ? selectedIds.length > 0 : (activeTab === 'requests' ? selectedRequestIds.length > 0 : false);

  return (
    <div className="space-y-8 relative pb-20">
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-sky-100 text-sky-600 rounded-lg"><Users size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Total Students</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.total}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-emerald-100 text-emerald-600 rounded-lg"><CheckCircle2 size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Registered</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.registered}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-amber-100 text-amber-600 rounded-lg"><Clock size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Under Process</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.pending}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-red-100 text-red-600 rounded-lg"><AlertCircle size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Open Requests</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.requests}</div>
        </div>
      </div>

      <div className="flex items-center justify-between border-b border-slate-200 pb-4">
        <div className="flex gap-8">
          <button 
            onClick={() => setActiveTab('students')}
            className={`pb-4 px-2 font-medium transition-all ${activeTab === 'students' ? 'text-sky-600 border-b-2 border-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Student Master List
          </button>
          <button 
            onClick={() => setActiveTab('requests')}
            className={`pb-4 px-2 font-medium transition-all ${activeTab === 'requests' ? 'text-sky-600 border-b-2 border-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Schedule Adjustments
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`pb-4 px-2 font-medium transition-all ${activeTab === 'history' ? 'text-sky-600 border-b-2 border-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <div className="flex items-center gap-2">
              <History size={16} />
              History Log
            </div>
          </button>
        </div>
        <div className="flex items-center gap-3">
          {activeTab === 'students' && (
            <>
              <button 
                onClick={downloadInitialTemplate}
                className="text-xs font-bold text-slate-500 hover:text-slate-700 underline underline-offset-4"
              >
                Downloads template
              </button>
              <label className="flex items-center gap-2 px-4 py-2 bg-sky-600 text-white rounded-lg hover:bg-sky-700 cursor-pointer transition-colors text-sm font-medium shadow-sm">
                <FileUp size={16} />
                Import Admissions
                <input type="file" className="hidden" onChange={handleFileUpload} accept=".xlsx, .xls, .csv" />
              </label>
              <button 
                onClick={downloadData}
                className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium shadow-sm"
              >
                <Download size={16} />
                Export for Banner
              </button>
            </>
          )}
          {activeTab === 'requests' && (
            <button 
              onClick={downloadRequestsData}
              className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium shadow-sm"
            >
              <FileSpreadsheet size={16} />
              Export Requests
            </button>
          )}
        </div>
      </div>

      {activeTab === 'students' && (
        <>
          <div className="flex items-center gap-4 mb-2 overflow-x-auto pb-2 scrollbar-hide">
            <div className="flex items-center gap-2 text-slate-400 mr-2 shrink-0">
              <Filter size={16} />
              <span className="text-xs font-bold uppercase tracking-wider">Filter by Term:</span>
            </div>
            <div className="flex gap-2">
              {uniqueTerms.map((term) => (
                <button
                  key={term}
                  onClick={() => {
                    setSelectedTerm(term);
                    setSelectedIds([]);
                  }}
                  className={`px-4 py-2 rounded-xl text-sm font-bold transition-all border ${
                    selectedTerm === term 
                      ? 'bg-sky-600 border-sky-600 text-white shadow-md shadow-sky-100' 
                      : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                  }`}
                >
                  {term === 'All' ? 'All Terms' : `Term ${term}`}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 text-slate-500 text-sm font-medium">
                <tr>
                  <th className="px-6 py-4 w-12">
                    <button 
                      onClick={toggleSelectAll}
                      className={`transition-colors ${selectedIds.length === filteredStudents.length && filteredStudents.length > 0 ? 'text-sky-600' : 'text-slate-300 hover:text-slate-400'}`}
                    >
                      {selectedIds.length === filteredStudents.length && filteredStudents.length > 0 ? <CheckSquare size={20} /> : <Square size={20} />}
                    </button>
                  </th>
                  <th className="px-6 py-4">Student ID</th>
                  <th className="px-6 py-4">Name</th>
                  <th className="px-6 py-4">Term</th>
                  <th className="px-6 py-4">Section Number</th>
                  <th className="px-6 py-4">Academic Level</th>
                  <th className="px-6 py-4">Placements (E/M)</th>
                  <th className="px-6 py-4 text-center">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 text-slate-700">
                {filteredStudents.map((student) => (
                  <tr 
                    key={student.id} 
                    className={`transition-colors ${selectedIds.includes(student.id) ? 'bg-sky-50/50' : 'hover:bg-slate-50'}`}
                  >
                    <td className="px-6 py-4">
                      <button 
                        onClick={() => toggleSelectOne(student.id)}
                        className={`transition-colors ${selectedIds.includes(student.id) ? 'text-sky-600' : 'text-slate-300 hover:text-slate-400'}`}
                      >
                        {selectedIds.includes(student.id) ? <CheckSquare size={20} /> : <Square size={20} />}
                      </button>
                    </td>
                    <td className="px-6 py-4 font-mono text-sm font-bold text-slate-900">{student.id}</td>
                    <td className="px-6 py-4">
                      <div className="font-semibold text-slate-800">{student.name}</div>
                      <div className="text-xs text-slate-400 uppercase font-bold tracking-wider">{student.admittedMajor}</div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-xs font-black text-slate-500 bg-slate-100 px-2 py-1 rounded">
                        {student.term}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-sm font-mono font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">
                        E:{student.englishSection || '-'} M:{student.mathSection || '-'}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${student.academicLevel === 'Prep' ? 'bg-indigo-100 text-indigo-700' : 'bg-emerald-100 text-emerald-700'}`}>
                        {student.academicLevel}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-[11px] font-bold">
                      <span className="text-slate-400 uppercase mr-1">E:</span> 
                      <span className={student.englishPlacement === 'Pending' ? 'text-amber-500' : 'text-slate-700'}>{student.englishPlacement}</span>
                      <br/>
                      <span className="text-slate-400 uppercase mr-1">M:</span> 
                      <span className={student.mathPlacement === 'Pending' ? 'text-amber-500' : 'text-slate-700'}>{student.mathPlacement}</span>
                    </td>
                    <td className="px-6 py-4">
                      <select
                        value={student.status}
                        onChange={(e) => updateStatus(student.id, e.target.value as RegistrationStatus)}
                        className={`w-full p-2 rounded-lg text-sm font-bold outline-none border transition-all ${
                          student.status === RegistrationStatus.REGISTERED 
                            ? 'bg-emerald-50 border-emerald-200 text-emerald-700' 
                            : 'bg-amber-50 border-amber-200 text-amber-700'
                        }`}
                      >
                        <option value={RegistrationStatus.UNDER_PROCESS}>Under Process</option>
                        <option value={RegistrationStatus.REGISTERED}>Registered</option>
                      </select>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredStudents.length === 0 && (
              <div className="p-12 text-center text-slate-400">
                No students found for this term.
              </div>
            )}
          </div>
        </>
      )}

      {activeTab === 'requests' && (
        <div className="space-y-4">
          {requests.length > 0 && (
            <div className="flex items-center gap-3 px-4 py-2 mb-2 bg-slate-50 rounded-xl border border-slate-200 w-fit">
              <button 
                onClick={toggleSelectAll}
                className={`flex items-center gap-2 text-sm font-bold transition-colors ${selectedRequestIds.length === requests.filter(r => r.status === 'Pending').length ? 'text-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
              >
                {selectedRequestIds.length === requests.filter(r => r.status === 'Pending').length ? <CheckSquare size={18} /> : <Square size={18} />}
                Select All Pending
              </button>
            </div>
          )}

          <div className="grid gap-4">
            {requests.length === 0 ? (
              <div className="bg-white p-12 text-center text-slate-400 rounded-2xl border border-slate-200 border-dashed">
                No pending schedule adjustment requests.
              </div>
            ) : (
              requests.map((request) => (
                <div 
                  key={request.id} 
                  className={`bg-white p-6 rounded-2xl shadow-sm border transition-all flex items-center gap-6 ${selectedRequestIds.includes(request.id) ? 'border-sky-300 bg-sky-50/30' : 'border-slate-200'}`}
                >
                  {request.status === 'Pending' && (
                    <button 
                      onClick={() => toggleSelectOne(request.id)}
                      className={`transition-colors shrink-0 ${selectedRequestIds.includes(request.id) ? 'text-sky-600' : 'text-slate-300 hover:text-slate-400'}`}
                    >
                      {selectedRequestIds.includes(request.id) ? <CheckSquare size={24} /> : <Square size={24} />}
                    </button>
                  )}

                  <div className="flex-1">
                    <div className="flex items-center gap-3 mb-1">
                      <span className={`text-[10px] font-black uppercase tracking-[0.1em] px-2 py-0.5 rounded ${
                        request.requestType === 'Section Change' ? 'bg-sky-100 text-sky-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {request.requestType}
                      </span>
                      <span className="text-xs text-slate-400 font-medium">Submitted {new Date(request.createdAt).toLocaleDateString()}</span>
                    </div>
                    <h3 className="font-bold text-slate-900">{request.studentName} <span className="text-slate-400 text-sm font-normal">({request.studentId})</span></h3>
                    <p className="text-slate-600 mt-2 text-sm leading-relaxed">{request.details}</p>
                  </div>

                  <div className="flex items-center gap-4">
                    {request.status === 'Processed' ? (
                      <span className="flex items-center gap-1.5 text-emerald-600 font-bold bg-emerald-50 px-4 py-2 rounded-xl border border-emerald-100">
                        <CheckCircle2 size={18} />
                        Finished
                      </span>
                    ) : (
                      <button 
                        onClick={() => processRequest(request.id)}
                        className="px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-xl hover:bg-slate-50 transition-colors font-bold text-sm shadow-sm"
                      >
                        Mark Finished
                      </button>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Search history by ID, Name, Action or Event Type..."
              value={logSearch}
              onChange={(e) => setLogSearch(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-white border border-slate-200 rounded-2xl shadow-sm focus:ring-2 focus:ring-sky-500 outline-none transition-all font-medium text-slate-400"
            />
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
              <h3 className="font-bold text-slate-900 flex items-center gap-2">
                <History size={18} className="text-sky-600" />
                Student Activity History Log
              </h3>
              <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">{filteredLogs.length} Events Total</span>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                  <tr>
                    <th className="px-6 py-4">Date & Time</th>
                    <th className="px-6 py-4">Student ID</th>
                    <th className="px-6 py-4">Student Name</th>
                    <th className="px-6 py-4">Event Type</th>
                    <th className="px-6 py-4">Action Details</th>
                    <th className="px-6 py-4">Actor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-slate-700">
                  {filteredLogs.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="p-20 text-center text-slate-400">
                        <History size={48} className="mx-auto mb-4 opacity-10" />
                        <p className="font-medium">No activity log entries found.</p>
                      </td>
                    </tr>
                  ) : (
                    filteredLogs.map((log) => (
                      <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="flex items-center gap-2 text-xs font-medium text-slate-500">
                            <Calendar size={12} className="text-slate-400" />
                            {new Date(log.timestamp).toLocaleDateString()}
                          </div>
                          <div className="flex items-center gap-2 text-[10px] text-slate-400 ml-5">
                            <Clock size={10} />
                            {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className="font-mono text-xs font-bold text-slate-900 bg-slate-100 px-2 py-1 rounded">
                            {log.studentId || 'SYSTEM'}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <div className="font-semibold text-sm text-slate-800">
                            {log.studentName || 'System Process'}
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                            log.type === 'Admission' ? 'bg-sky-100 text-sky-700' :
                            log.type === 'Placement' ? 'bg-indigo-100 text-indigo-700' :
                            log.type === 'StatusUpdate' ? 'bg-emerald-100 text-emerald-700' :
                            'bg-amber-100 text-amber-700'
                          }`}>
                            {log.type}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-sm text-slate-600 font-medium leading-relaxed max-w-md">
                            {log.description}
                          </p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-2">
                            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold ${
                              log.actor === 'Registrar' ? 'bg-slate-800 text-white' : 'bg-amber-100 text-amber-700'
                            }`}>
                              {log.actor.charAt(0)}
                            </div>
                            <span className="text-xs font-bold text-slate-600">{log.actor}</span>
                          </div>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* Bulk Action Toolbar */}
      {anySelected && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-6 z-50 border border-slate-700 animate-in fade-in slide-in-from-bottom-4">
          <div className="flex items-center gap-3 pr-6 border-r border-slate-700">
            <div className="w-8 h-8 bg-sky-500 rounded-lg flex items-center justify-center font-bold text-sm">
              {activeTab === 'students' ? selectedIds.length : selectedRequestIds.length}
            </div>
            <span className="text-sm font-semibold">{activeTab === 'students' ? 'Students' : 'Requests'} Selected</span>
          </div>
          <div className="flex items-center gap-3">
            <span className="text-xs text-slate-400 font-bold uppercase tracking-wider">Bulk Actions:</span>

            {activeTab === 'students' ? (
              <>
                <button 
                  onClick={() => handleBulkStatusUpdate(RegistrationStatus.REGISTERED)}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-500 rounded-xl text-sm font-bold transition-colors"
                >
                  <CheckCircle2 size={16} />
                  Mark Registered
                </button>
                <button 
                  onClick={() => handleBulkStatusUpdate(RegistrationStatus.UNDER_PROCESS)}
                  className="flex items-center gap-2 px-4 py-2 bg-amber-600 hover:bg-amber-500 rounded-xl text-sm font-bold transition-colors"
                >
                  <Clock size={16} />
                  Mark Under Process
                </button>
              </>
            ) : (
              <button 
                onClick={handleBulkRequestProcess}
                className="flex items-center gap-2 px-4 py-2 bg-sky-600 hover:bg-sky-500 rounded-xl text-sm font-bold transition-colors"
              >
                <CheckCircle size={16} />
                Mark all as Finished
              </button>
            )}

            <button 
              onClick={() => activeTab === 'students' ? setSelectedIds([]) : setSelectedRequestIds([])}
              className="px-4 py-2 text-slate-400 hover:text-white text-sm font-medium"
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default RegistrarDashboard;

export enum UserRole {
  REGISTRAR = 'REGISTRAR',
  PREP_DEPT = 'PREP_DEPT',
  STUDENT = 'STUDENT'
}

export enum AcademicLevel {
  PREP = 'Prep',
  FRESHMAN = 'Freshmen'
}

export enum RegistrationStatus {
  UNDER_PROCESS = 'Under Process',
  REGISTERED = 'Registered'
}

export interface Student {
  id: string;
  name: string;
  gender: 'Male' | 'Female';
  admittedMajor: string;
  term: string;
  englishPlacement: string;
  mathPlacement: string;
  academicLevel: AcademicLevel;
  status: RegistrationStatus;
  updatedAt: string;
  englishSection?: string;
  mathSection?: string;
}

export interface ScheduleRequest {
  id: string;
  studentId: string;
  studentName: string;
  requestType: 'Section Change' | 'English Shift';
  details: string;
  courseName?: string;
  sectionNumber?: string;
  status: 'Pending' | 'Registered' | 'Needs Revision';
  createdAt: string;
}

export interface ActivityLog {
  id: string;
  type: 'Admission' | 'Placement' | 'StatusUpdate' | 'Adjustment';
  description: string;
  studentId?: string;
  studentName?: string;
  timestamp: string;
  actor: string;
}

export interface AuthState {
  role: UserRole | null;
  studentId?: string;
}

import React, { useState, useMemo } from 'react';
import { Student, RegistrationStatus, ScheduleRequest, AcademicLevel, ActivityLog } from '../types';
import { FileUp, Download, CheckCircle2, Clock, AlertCircle, Users, CheckSquare, Square, CheckCircle, Filter, FileSpreadsheet, History, Search, UserCheck, FileText, Calendar, RotateCcw } from 'lucide-react';
import * as XLSX from 'xlsx';

interface RegistrarDashboardProps {
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  requests: ScheduleRequest[];
  setRequests: React.Dispatch<React.SetStateAction<ScheduleRequest[]>>;
  logs: ActivityLog[];
  addLog: (type: ActivityLog['type'], description: string, actor: string, studentId?: string, studentName?: string) => void;
}

const RegistrarDashboard: React.FC<RegistrarDashboardProps> = ({ students, setStudents, requests, setRequests, logs, addLog }) => {
  const [activeTab, setActiveTab] = useState<'students' | 'requests' | 'history'>('students');
  const [selectedTerm, setSelectedTerm] = useState<string>('All');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [selectedRequestIds, setSelectedRequestIds] = useState<string[]>([]);
  const [logSearch, setLogSearch] = useState('');

  const uniqueTerms = useMemo(() => {
    const terms = Array.from(new Set(students.map(s => s.term))).sort().reverse();
    return ['All', ...terms];
  }, [students]);

  const filteredStudents = useMemo(() => {
    if (selectedTerm === 'All') return students;
    return students.filter(s => s.term === selectedTerm);
  }, [students, selectedTerm]);

  const filteredLogs = useMemo(() => {
    if (!logSearch) return logs;
    const search = logSearch.toLowerCase();
    return logs.filter(l => 
      l.description.toLowerCase().includes(search) || 
      l.type.toLowerCase().includes(search) ||
      l.studentId?.toLowerCase().includes(search) ||
      l.studentName?.toLowerCase().includes(search)
    );
  }, [logs, logSearch]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        const newStudents: Student[] = data.map((row: any) => ({
          id: String(row.ID || row.id || ''),
          name: String(row.Name || row.name || 'Unknown Student'),
          gender: (row.Gender || row.gender || 'Male') as 'Male' | 'Female',
          admittedMajor: String(row.Major || row.major || 'Undecided'),
          term: String(row.Term || row.term || '261'),
          englishPlacement: 'Pending',
          mathPlacement: 'Pending',
          academicLevel: AcademicLevel.PREP,
          status: RegistrationStatus.UNDER_PROCESS,
          updatedAt: new Date().toISOString(),
          englishSection: row['English Section'] || row.english_section ? String(row['English Section'] || row.english_section) : undefined,
          mathSection: row['Math Section'] || row.math_section ? String(row['Math Section'] || row.math_section) : undefined
        })).filter(s => s.id !== '');

        setStudents(prev => {
          const existingIds = new Set(prev.map(s => s.id));
          const filteredNew = newStudents.filter(s => !existingIds.has(s.id));
          addLog('Admission', `Imported ${filteredNew.length} new student records from Excel.`, 'Registrar');
          return [...prev, ...filteredNew];
        });

        alert(`Successfully imported ${newStudents.length} base student records.`);
      } catch (err) {
        alert("Error importing data. Please ensure the Excel file matches the template headers.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const downloadInitialTemplate = () => {
    const templateData = [
      { ID: '20241001', Name: 'Ahmed Al-Fulan', Gender: 'Male', Major: 'Mechanical Engineering', Term: '261' },
      { ID: '20241002', Name: 'Sara Al-Fulan', Gender: 'Female', Major: 'Computer Science', Term: '261' },
      { ID: '20241003', Name: 'Khalid Abdullah', Gender: 'Male', Major: 'Industrial Design', Term: '262' }
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Admissions_Template");
    XLSX.writeFile(wb, "Initial_Students_Template.xlsx");
  };

  const updateStatus = (id: string, newStatus: RegistrationStatus) => {
    const student = students.find(s => s.id === id);
    if (student) {
      addLog('StatusUpdate', `Status changed to ${newStatus}.`, 'Registrar', student.id, student.name);
    }
    setStudents(prev => prev.map(s => s.id === id ? { ...s, status: newStatus, updatedAt: new Date().toISOString() } : s));
  };

  const handleBulkStatusUpdate = (newStatus: RegistrationStatus) => {
    selectedIds.forEach(id => {
      const student = students.find(s => s.id === id);
      if (student) {
        addLog('StatusUpdate', `Bulk update: status set to ${newStatus}.`, 'Registrar', student.id, student.name);
      }
    });
    setStudents(prev => prev.map(s => 
      selectedIds.includes(s.id) ? { ...s, status: newStatus, updatedAt: new Date().toISOString() } : s
    ));
    setSelectedIds([]);
  };

  const handleBulkRequestProcess = (status: 'Registered' | 'Needs Revision') => {
    selectedRequestIds.forEach(id => {
      const req = requests.find(r => r.id === id);
      if (req) {
        addLog('Adjustment', `Bulk update: Mark as ${status} for ${req.requestType}.`, 'Registrar', req.studentId, req.studentName);
      }
    });
    setRequests(prev => prev.map(r => 
      selectedRequestIds.includes(r.id) ? { ...r, status: status } : r
    ));
    setSelectedRequestIds([]);
  };

  const toggleSelectAll = () => {
    if (activeTab === 'students') {
      if (selectedIds.length === filteredStudents.length) {
        setSelectedIds([]);
      } else {
        setSelectedIds(filteredStudents.map(s => s.id));
      }
    } else if (activeTab === 'requests') {
      const pendingRequests = requests.filter(r => r.status === 'Pending');
      if (selectedRequestIds.length === pendingRequests.length) {
        setSelectedRequestIds([]);
      } else {
        setSelectedRequestIds(pendingRequests.map(r => r.id));
      }
    }
  };

  const toggleSelectOne = (id: string) => {
    if (activeTab === 'students') {
      setSelectedIds(prev => 
        prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
      );
    } else {
      setSelectedRequestIds(prev => 
        prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
      );
    }
  };

  const updateRequestStatus = (requestId: string, status: 'Registered' | 'Needs Revision') => {
    const req = requests.find(r => r.id === requestId);
    if (req) {
      addLog('Adjustment', `Marked ${req.requestType} as ${status}.`, 'Registrar', req.studentId, req.studentName);
    }
    setRequests(prev => prev.map(r => r.id === requestId ? { ...r, status } : r));
  };

  const downloadData = () => {
    const exportData = students.map(s => ({
      'Student ID': s.id,
      'Name': s.name,
      'Gender': s.gender,
      'Major': s.admittedMajor,
      'Term': s.term,
      'English Section': s.englishSection || 'N/A',
      'Math Section': s.mathSection || 'N/A',
      'English Placement': s.englishPlacement,
      'Math Placement': s.mathPlacement,
      'Academic Level': s.academicLevel,
      'Registration Status': s.status,
      'Last Updated': new Date(s.updatedAt).toLocaleString()
    }));

    const worksheet = XLSX.utils.json_to_sheet(exportData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, 'Students');
    XLSX.writeFile(workbook, `Banner_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const downloadRequestsData = () => {
    const exportData = requests.map(r => ({
      'Request ID': r.id,
      'Student ID': r.studentId,
      'Student Name': r.studentName,
      'Request Type': r.requestType,
      'Course': r.courseName || 'N/A',
      'Section Number': r.sectionNumber || 'N/A',
      'Adjustment Details': r.details,
      'Status': r.status,
      'Submitted Date': new Date(r.createdAt).toLocaleString()
    }));

    const worksheet = XLSX.utils.json_to_sheet(exportData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, 'Adjustment Requests');
    XLSX.writeFile(workbook, `Adjustment_Requests_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const stats = {
    total: students.length,
    registered: students.filter(s => s.status === RegistrationStatus.REGISTERED).length,
    pending: students.filter(s => s.status === RegistrationStatus.UNDER_PROCESS).length,
    requests: requests.filter(r => r.status === 'Pending').length,
  };

  const anySelected = activeTab === 'students' ? selectedIds.length > 0 : (activeTab === 'requests' ? selectedRequestIds.length > 0 : false);

  return (
    <div className="space-y-8 relative pb-20">
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-sky-100 text-sky-600 rounded-lg"><Users size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Total Students</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.total}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-emerald-100 text-emerald-600 rounded-lg"><CheckCircle2 size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Registered</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.registered}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-amber-100 text-amber-600 rounded-lg"><Clock size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Under Process</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.pending}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div className="p-2 bg-red-100 text-red-600 rounded-lg"><AlertCircle size={20} /></div>
            <span className="text-xs font-medium text-slate-400">Open Requests</span>
          </div>
          <div className="text-2xl font-bold text-slate-900">{stats.requests}</div>
        </div>
      </div>

      <div className="flex items-center justify-between border-b border-slate-200 pb-4">
        <div className="flex gap-8">
          <button 
            onClick={() => setActiveTab('students')}
            className={`pb-4 px-2 font-medium transition-all ${activeTab === 'students' ? 'text-sky-600 border-b-2 border-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Student Master List
          </button>
          <button 
            onClick={() => setActiveTab('requests')}
            className={`pb-4 px-2 font-medium transition-all ${activeTab === 'requests' ? 'text-sky-600 border-b-2 border-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Schedule Adjustments
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`pb-4 px-2 font-medium transition-all ${activeTab === 'history' ? 'text-sky-600 border-b-2 border-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <div className="flex items-center gap-2">
              <History size={16} />
              History Log
            </div>
          </button>
        </div>
        <div className="flex items-center gap-3">
          {activeTab === 'students' && (
            <>
              <button 
                onClick={downloadInitialTemplate}
                className="text-xs font-bold text-slate-500 hover:text-slate-700 underline underline-offset-4"
              >
                Downloads template
              </button>
              <label className="flex items-center gap-2 px-4 py-2 bg-sky-600 text-white rounded-lg hover:bg-sky-700 cursor-pointer transition-colors text-sm font-medium shadow-sm">
                <FileUp size={16} />
                Import Admissions
                <input type="file" className="hidden" onChange={handleFileUpload} accept=".xlsx, .xls, .csv" />
              </label>
              <button 
                onClick={downloadData}
                className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium shadow-sm"
              >
                <Download size={16} />
                Export for Banner
              </button>
            </>
          )}
          {activeTab === 'requests' && (
            <button 
              onClick={downloadRequestsData}
              className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium shadow-sm"
            >
              <FileSpreadsheet size={16} />
              Export Requests
            </button>
          )}
        </div>
      </div>

      {activeTab === 'students' && (
        <>
          <div className="flex items-center gap-4 mb-2 overflow-x-auto pb-2 scrollbar-hide">
            <div className="flex items-center gap-2 text-slate-400 mr-2 shrink-0">
              <Filter size={16} />
              <span className="text-xs font-bold uppercase tracking-wider">Filter by Term:</span>
            </div>
            <div className="flex gap-2">
              {uniqueTerms.map((term) => (
                <button
                  key={term}
                  onClick={() => {
                    setSelectedTerm(term);
                    setSelectedIds([]);
                  }}
                  className={`px-4 py-2 rounded-xl text-sm font-bold transition-all border ${
                    selectedTerm === term 
                      ? 'bg-sky-600 border-sky-600 text-white shadow-md shadow-sky-100' 
                      : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                  }`}
                >
                  {term === 'All' ? 'All Terms' : `Term ${term}`}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 text-slate-500 text-sm font-medium">
                <tr>
                  <th className="px-6 py-4 w-12">
                    <button 
                      onClick={toggleSelectAll}
                      className={`transition-colors ${selectedIds.length === filteredStudents.length && filteredStudents.length > 0 ? 'text-sky-600' : 'text-slate-300 hover:text-slate-400'}`}
                    >
                      {selectedIds.length === filteredStudents.length && filteredStudents.length > 0 ? <CheckSquare size={20} /> : <Square size={20} />}
                    </button>
                  </th>
                  <th className="px-6 py-4">Student ID</th>
                  <th className="px-6 py-4">Name</th>
                  <th className="px-6 py-4">Term</th>
                  <th className="px-6 py-4">Section Number</th>
                  <th className="px-6 py-4">Academic Level</th>
                  <th className="px-6 py-4">Placements (E/M)</th>
                  <th className="px-6 py-4 text-center">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 text-slate-700">
                {filteredStudents.map((student) => (
                  <tr 
                    key={student.id} 
                    className={`transition-colors ${selectedIds.includes(student.id) ? 'bg-sky-50/50' : 'hover:bg-slate-50'}`}
                  >
                    <td className="px-6 py-4">
                      <button 
                        onClick={() => toggleSelectOne(student.id)}
                        className={`transition-colors ${selectedIds.includes(student.id) ? 'text-sky-600' : 'text-slate-300 hover:text-slate-400'}`}
                      >
                        {selectedIds.includes(student.id) ? <CheckSquare size={20} /> : <Square size={20} />}
                      </button>
                    </td>
                    <td className="px-6 py-4 font-mono text-sm font-bold text-slate-900">{student.id}</td>
                    <td className="px-6 py-4">
                      <div className="font-semibold text-slate-800">{student.name}</div>
                      <div className="text-xs text-slate-400 uppercase font-bold tracking-wider">{student.admittedMajor}</div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-xs font-black text-slate-500 bg-slate-100 px-2 py-1 rounded">
                        {student.term}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-sm font-mono font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">
                        E:{student.englishSection || '-'} M:{student.mathSection || '-'}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${student.academicLevel === 'Prep' ? 'bg-indigo-100 text-indigo-700' : 'bg-emerald-100 text-emerald-700'}`}>
                        {student.academicLevel}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-[11px] font-bold">
                      <span className="text-slate-400 uppercase mr-1">E:</span> 
                      <span className={student.englishPlacement === 'Pending' ? 'text-amber-500' : 'text-slate-700'}>{student.englishPlacement}</span>
                      <br/>
                      <span className="text-slate-400 uppercase mr-1">M:</span> 
                      <span className={student.mathPlacement === 'Pending' ? 'text-amber-500' : 'text-slate-700'}>{student.mathPlacement}</span>
                    </td>
                    <td className="px-6 py-4">
                      <select
                        value={student.status}
                        onChange={(e) => updateStatus(student.id, e.target.value as RegistrationStatus)}
                        className={`w-full p-2 rounded-lg text-sm font-bold outline-none border transition-all ${
                          student.status === RegistrationStatus.REGISTERED 
                            ? 'bg-emerald-50 border-emerald-200 text-emerald-700' 
                            : 'bg-amber-50 border-amber-200 text-amber-700'
                        }`}
                      >
                        <option value={RegistrationStatus.UNDER_PROCESS}>Under Process</option>
                        <option value={RegistrationStatus.REGISTERED}>Registered</option>
                      </select>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredStudents.length === 0 && (
              <div className="p-12 text-center text-slate-400">
                No students found for this term.
              </div>
            )}
          </div>
        </>
      )}

      {activeTab === 'requests' && (
        <div className="space-y-4">
          {requests.length > 0 && (
            <div className="flex items-center gap-3 px-4 py-2 mb-2 bg-slate-50 rounded-xl border border-slate-200 w-fit">
              <button 
                onClick={toggleSelectAll}
                className={`flex items-center gap-2 text-sm font-bold transition-colors ${selectedRequestIds.length === requests.filter(r => r.status === 'Pending').length ? 'text-sky-600' : 'text-slate-500 hover:text-slate-700'}`}
              >
                {selectedRequestIds.length === requests.filter(r => r.status === 'Pending').length ? <CheckSquare size={18} /> : <Square size={18} />}
                Select All Pending
              </button>
            </div>
          )}

          <div className="grid gap-4">
            {requests.length === 0 ? (
              <div className="bg-white p-12 text-center text-slate-400 rounded-2xl border border-slate-200 border-dashed">
                No pending schedule adjustment requests.
              </div>
            ) : (
              requests.map((request) => (
                <div 
                  key={request.id} 
                  className={`bg-white p-6 rounded-2xl shadow-sm border transition-all flex items-center gap-6 ${selectedRequestIds.includes(request.id) ? 'border-sky-300 bg-sky-50/30' : 'border-slate-200'}`}
                >
                  {request.status === 'Pending' && (
                    <button 
                      onClick={() => toggleSelectOne(request.id)}
                      className={`transition-colors shrink-0 ${selectedRequestIds.includes(request.id) ? 'text-sky-600' : 'text-slate-300 hover:text-slate-400'}`}
                    >
                      {selectedRequestIds.includes(request.id) ? <CheckSquare size={24} /> : <Square size={24} />}
                    </button>
                  )}

                  <div className="flex-1">
                    <div className="flex items-center gap-3 mb-1">
                      <span className={`text-[10px] font-black uppercase tracking-[0.1em] px-2 py-0.5 rounded ${
                        request.requestType === 'Section Change' ? 'bg-sky-100 text-sky-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {request.requestType}
                      </span>
                      <span className="text-xs text-slate-400 font-medium">Submitted {new Date(request.createdAt).toLocaleDateString()}</span>
                    </div>
                    <h3 className="font-bold text-slate-900">{request.studentName} <span className="text-slate-400 text-sm font-normal">({request.studentId})</span></h3>
                    <p className="text-slate-600 mt-2 text-sm leading-relaxed italic">"{request.details}"</p>
                  </div>

                  <div className="flex items-center gap-3">
                    {request.status === 'Registered' ? (
                      <span className="flex items-center gap-1.5 text-emerald-600 font-bold bg-emerald-50 px-4 py-2 rounded-xl border border-emerald-100">
                        <CheckCircle2 size={18} />
                        Registered
                      </span>
                    ) : request.status === 'Needs Revision' ? (
                      <span className="flex items-center gap-1.5 text-amber-600 font-bold bg-amber-50 px-4 py-2 rounded-xl border border-amber-100">
                        <RotateCcw size={18} />
                        Revision Required
                      </span>
                    ) : (
                      <div className="flex gap-2">
                        <button 
                          onClick={() => updateRequestStatus(request.id, 'Registered')}
                          className="px-4 py-2 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition-colors font-bold text-sm shadow-sm flex items-center gap-2"
                        >
                          <CheckCircle2 size={16} />
                          Register
                        </button>
                        <button 
                          onClick={() => updateRequestStatus(request.id, 'Needs Revision')}
                          className="px-4 py-2 bg-white border border-slate-200 text-amber-600 rounded-xl hover:bg-amber-50 transition-colors font-bold text-sm shadow-sm flex items-center gap-2"
                        >
                          <RotateCcw size={16} />
                          Revision Needed
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="space-y-6">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Search history by ID, Name, Action or Event Type..."
              value={logSearch}
              onChange={(e) => setLogSearch(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-white border border-slate-200 rounded-2xl shadow-sm focus:ring-2 focus:ring-sky-500 outline-none transition-all font-medium text-slate-400"
            />
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
              <h3 className="font-bold text-slate-900 flex items-center gap-2">
                <History size={18} className="text-sky-600" />
                Student Activity History Log
              </h3>
              <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">{filteredLogs.length} Events Total</span>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                  <tr>
                    <th className="px-6 py-4">Date & Time</th>
                    <th className="px-6 py-4">Student ID</th>
                    <th className="px-6 py-4">Student Name</th>
                    <th className="px-6 py-4">Event Type</th>
                    <th className="px-6 py-4">Action Details</th>
                    <th className="px-6 py-4">Actor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-slate-700">
                  {filteredLogs.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="p-20 text-center text-slate-400">
                        <History size={48} className="mx-auto mb-4 opacity-10" />
                        <p className="font-medium">No activity log entries found.</p>
                      </td>
                    </tr>
                  ) : (
                    filteredLogs.map((log) => (
                      <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="flex items-center gap-2 text-xs font-medium text-slate-500">
                            <Calendar size={12} className="text-slate-400" />
                            {new Date(log.timestamp).toLocaleDateString()}
                          </div>
                          <div className="flex items-center gap-2 text-[10px] text-slate-400 ml-5">
                            <Clock size={10} />
                            {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className="font-mono text-xs font-bold text-slate-900 bg-slate-100 px-2 py-1 rounded">
                            {log.studentId || 'SYSTEM'}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <div className="font-semibold text-sm text-slate-800">
                            {log.studentName || 'System Process'}
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                            log.type === 'Admission' ? 'bg-sky-100 text-sky-700' :
                            log.type === 'Placement' ? 'bg-indigo-100 text-indigo-700' :
                            log.type === 'StatusUpdate' ? 'bg-emerald-100 text-emerald-700' :
                            'bg-amber-100 text-amber-700'
                          }`}>
                            {log.type}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-sm text-slate-600 font-medium leading-relaxed max-w-md">
                            {log.description}
                          </p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-2">
                            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold ${
                              log.actor === 'Registrar' ? 'bg-slate-800 text-white' : 'bg-amber-100 text-amber-700'
                            }`}>
                              {log.actor.charAt(0)}
                            </div>
                            <span className="text-xs font-bold text-slate-600">{log.actor}</span>
                          </div>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* Bulk Action Toolbar */}
      {anySelected && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-6 z-50 border border-slate-700 animate-in fade-in slide-in-from-bottom-4">
          <div className="flex items-center gap-3 pr-6 border-r border-slate-700">
            <div className="w-8 h-8 bg-sky-500 rounded-lg flex items-center justify-center font-bold text-sm">
              {activeTab === 'students' ? selectedIds.length : selectedRequestIds.length}
            </div>
            <span className="text-sm font-semibold">{activeTab === 'students' ? 'Students' : 'Requests'} Selected</span>
          </div>
          <div className="flex items-center gap-3">
            <span className="text-xs text-slate-400 font-bold uppercase tracking-wider">Bulk Actions:</span>

            {activeTab === 'students' ? (
              <>
                <button 
                  onClick={() => handleBulkStatusUpdate(RegistrationStatus.REGISTERED)}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-500 rounded-xl text-sm font-bold transition-colors"
                >
                  <CheckCircle2 size={16} />
                  Mark Registered
                </button>
                <button 
                  onClick={() => handleBulkStatusUpdate(RegistrationStatus.UNDER_PROCESS)}
                  className="flex items-center gap-2 px-4 py-2 bg-amber-600 hover:bg-amber-500 rounded-xl text-sm font-bold transition-colors"
                >
                  <Clock size={16} />
                  Mark Under Process
                </button>
              </>
            ) : (
              <div className="flex gap-2">
                <button 
                  onClick={() => handleBulkRequestProcess('Registered')}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-500 rounded-xl text-sm font-bold transition-colors"
                >
                  <CheckCircle size={16} />
                  Register Selected
                </button>
                <button 
                  onClick={() => handleBulkRequestProcess('Needs Revision')}
                  className="flex items-center gap-2 px-4 py-2 bg-amber-600 hover:bg-amber-500 rounded-xl text-sm font-bold transition-colors"
                >
                  <RotateCcw size={16} />
                  Mark Revision Needed
                </button>
              </div>
            )}

            <button 
              onClick={() => activeTab === 'students' ? setSelectedIds([]) : setSelectedRequestIds([])}
              className="px-4 py-2 text-slate-400 hover:text-white text-sm font-medium"
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default RegistrarDashboard;

import React, { useState, useMemo } from 'react';
import { Student, AcademicLevel, RegistrationStatus, ScheduleRequest, ActivityLog } from '../types';
import { FileUp, Send, CheckCircle2, History, Info, LayoutList, MessageSquarePlus, Download, Search, Hash, Book, RotateCcw } from 'lucide-react';
import * as XLSX from 'xlsx';

interface PrepDashboardProps {
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  requests: ScheduleRequest[];
  setRequests: React.Dispatch<React.SetStateAction<ScheduleRequest[]>>;
  addLog: (type: ActivityLog['type'], description: string, actor: string, studentId?: string, studentName?: string) => void;
}

const COURSE_LIST = [
  'ENGL001', 'ENGL002', 'ENGL003', 'ENGL004', 'ENGL005', 
  'MATH001', 'MATH002', 'MATH012', 
  'PYP 001', 'PYP 002', 
  'Modular Courses', 
  'PE 001', 'PE 002'
];

const PrepDashboard: React.FC<PrepDashboardProps> = ({ students, setStudents, requests, setRequests, addLog }) => {
  const [activeTab, setActiveTab] = useState<'placement' | 'adjustments'>('placement');
  const [selectedStudentId, setSelectedStudentId] = useState('');
  const [requestType, setRequestType] = useState<'Section Change' | 'English Shift'>('Section Change');
  const [requestDetails, setRequestDetails] = useState('');

  const [sectionNumber, setSectionNumber] = useState('');
  const [courseName, setCourseName] = useState('');

  const [statusSearch, setStatusSearch] = useState('');
  const [requestSearch, setRequestSearch] = useState('');

  const selectedStudent = useMemo(() => 
    students.find(s => s.id === selectedStudentId), 
    [students, selectedStudentId]
  );

  const isPrepSectionChange = selectedStudent?.academicLevel === AcademicLevel.PREP && requestType === 'Section Change';

  const handlePlacementUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        setStudents(prev => {
          const updatedStudents = [...prev];
          let updateCount = 0;
          let newCount = 0;

          data.forEach((row: any) => {
            const rowId = String(row.ID || row.id || '');
            if (!rowId) return;

            const eng = String(row.English || row.english || 'ENGL001');
            const math = String(row.Math || row.math || 'MATH001');

            const engSec = row['English Section'] || row.english_section ? String(row['English Section'] || row.english_section) : undefined;
            const mathSec = row['Math Section'] || row.math_section ? String(row['Math Section'] || row.math_section) : undefined;

            const isPromoted = eng.toLowerCase() === 'promoted' && math.toLowerCase() === 'promoted';
            const level = isPromoted ? AcademicLevel.FRESHMAN : AcademicLevel.PREP;

            const existingIndex = updatedStudents.findIndex(s => s.id === rowId);

            const detailString = `English: ${eng} (Sec: ${engSec || 'N/A'}) | Math: ${math} (Sec: ${mathSec || 'N/A'})`;

            if (existingIndex !== -1) {
              updatedStudents[existingIndex] = {
                ...updatedStudents[existingIndex],
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec || updatedStudents[existingIndex].englishSection,
                mathSection: mathSec || updatedStudents[existingIndex].mathSection,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              };
              updateCount++;
              addLog('Placement', `Updated Data: ${detailString}. Status reset to Under Process.`, 'Prep Dept', rowId, updatedStudents[existingIndex].name);
            } else {
              const newName = String(row.Name || row.name || 'External Record');
              updatedStudents.push({
                id: rowId,
                name: newName,
                gender: 'Male',
                admittedMajor: 'Not Provided',
                term: '241',
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec,
                mathSection: mathSec,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              });
              newCount++;
              addLog('Placement', `New Record: ${detailString}. Status: Under Process.`, 'Prep Dept', rowId, newName);
            }
          });

          alert(`Placement update complete: ${updateCount} students updated, ${newCount} new records created. All updated records reset to Under Process.`);
          return updatedStudents;
        });

      } catch (err) {
        console.error(err);
        alert("Error parsing file. Ensure columns include ID, English, Math, 'English Section', and 'Math Section'.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const downloadPlacementTemplate = () => {
    const templateData = [
      { ID: '20241001', English: 'Promoted', Math: 'MATH001', 'English Section': '45', 'Math Section': '55' },
      { ID: '20241002', English: 'ENGL001', Math: 'Promoted', 'English Section': '10', 'Math Section': '20' }
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Placements");
    XLSX.writeFile(wb, "Student_Placement_Template.xlsx");
  };

  const handleSubmitRequest = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStudent) {
      alert("Student ID not found.");
      return;
    }

    let finalDetails = requestDetails;
    if (isPrepSectionChange) {
      finalDetails = `[COURSE: ${courseName} | NEW SECTION: ${sectionNumber}]${requestDetails ? ' - ' + requestDetails : ''}`;
    }

    const newRequest: ScheduleRequest = {
      id: Math.random().toString(36).substr(2, 9),
      studentId: selectedStudent.id,
      studentName: selectedStudent.name,
      requestType,
      details: finalDetails || 'No justification provided.',
      courseName: isPrepSectionChange ? courseName : undefined,
      sectionNumber: isPrepSectionChange ? sectionNumber : undefined,
      status: 'Pending',
      createdAt: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    addLog('Adjustment', `Submitted ${requestType}: ${finalDetails || 'Request sent.'}`, 'Prep Dept', selectedStudent.id, selectedStudent.name);

    setRequestDetails('');
    setSectionNumber('');
    setCourseName('');
    setSelectedStudentId('');
    setRequestSearch('');
    alert("Schedule adjustment request sent to Registrar.");
  };

  const filteredStatusStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(statusSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(statusSearch.toLowerCase())
    );
  }, [students, statusSearch]);

  const filteredRequestStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(requestSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(requestSearch.toLowerCase())
    );
  }, [students, requestSearch]);

  const isSubmitDisabled = !selectedStudentId || (isPrepSectionChange && (!sectionNumber || !courseName));

  return (
    <div className="space-y-6">
      <div className="flex gap-4 border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('placement')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'placement' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <FileUp size={18} />
          Placement Control
        </button>
        <button 
          onClick={() => setActiveTab('adjustments')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'adjustments' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <MessageSquarePlus size={18} />
          Schedule Adjustments
        </button>
      </div>

      {activeTab === 'placement' ? (
        <div className="grid grid-cols-1 gap-8">
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-sky-100 text-sky-600 rounded-lg"><FileUp size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">Placement Processing</h2>
                  <p className="text-sm text-slate-500">Update existing students with test results</p>
                </div>
              </div>
              <button 
                onClick={downloadPlacementTemplate}
                className="flex items-center gap-2 text-xs font-bold text-sky-600 bg-sky-50 px-3 py-2 rounded-lg hover:bg-sky-100 transition-colors"
              >
                <Download size={14} />
                Download Placement Template
              </button>
            </div>

            <div className="grid grid-cols-1 gap-8">
              <div className="border-2 border-dashed border-slate-200 rounded-2xl p-10 text-center space-y-4 hover:border-sky-300 transition-colors bg-slate-50/30 group">
                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto text-slate-400 shadow-sm border border-slate-100 group-hover:scale-110 transition-transform">
                  <FileUp size={32} className="group-hover:text-sky-500" />
                </div>
                <div>
                  <p className="font-semibold text-slate-700">Drop Placement Excel here</p>
                  <p className="text-sm text-slate-400">Include 'English Section' and 'Math Section' columns</p>
                </div>
                <label className="inline-block px-6 py-3 bg-slate-900 text-white rounded-xl cursor-pointer hover:bg-slate-800 transition-all font-medium shadow-lg shadow-slate-200">
                  Import Test Results
                  <input type="file" className="hidden" onChange={handlePlacementUpload} accept=".xlsx, .xls, .csv" />
                </label>
              </div>
            </div>
          </div>

          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
             <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><History size={24} /></div>
                  <h2 className="text-xl font-bold text-slate-900">Live Status Monitor</h2>
                </div>
                <div className="relative w-full md:w-72">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <input
                    type="text"
                    placeholder="Search student by Name or ID..."
                    value={statusSearch}
                    onChange={(e) => setStatusSearch(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-sm font-medium text-slate-500"
                  />
                </div>
             </div>

             <div className="overflow-x-auto rounded-xl border border-slate-100">
               <table className="w-full text-left">
                 <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                   <tr>
                     <th className="px-6 py-4">Student</th>
                     <th className="px-6 py-4">Placement</th>
                     <th className="px-6 py-4">Section Number</th>
                     <th className="px-6 py-4">Academic Level</th>
                     <th className="px-6 py-4 text-center">Status</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                   {filteredStatusStudents.length === 0 ? (
                     <tr>
                       <td colSpan={5} className="px-6 py-12 text-center text-slate-400 font-medium">
                         No students found matching your search.
                       </td>
                     </tr>
                   ) : (
                     filteredStatusStudents.map(s => (
                       <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                         <td className="px-6 py-4">
                            <div className="font-bold text-slate-900">{s.name}</div>
                            <div className="text-xs text-slate-400 font-mono font-bold uppercase">{s.id}</div>
                         </td>
                         <td className="px-6 py-4">
                            <div className="flex gap-2">
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">E: {s.englishPlacement}</span>
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">M: {s.mathPlacement}</span>
                            </div>
                         </td>
                         <td className="px-6 py-4">
                           <span className="text-sm font-mono font-bold text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">
                             E:{s.englishSection || '-'} M:{s.mathSection || '-'}
                           </span>
                         </td>
                         <td className="px-6 py-4">
                           <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${s.academicLevel === 'Prep' ? 'bg-indigo-100 text-indigo-700' : 'bg-emerald-100 text-emerald-700'}`}>
                              {s.academicLevel}
                           </span>
                         </td>
                         <td className="px-6 py-4 text-center">
                            <span className={`inline-flex items-center gap-1.5 text-xs font-bold ${s.status === RegistrationStatus.REGISTERED ? 'text-emerald-600' : 'text-amber-600'}`}>
                               {s.status === RegistrationStatus.REGISTERED ? <CheckCircle2 size={14} /> : <div className="w-3.5 h-3.5 border-2 border-amber-600 border-t-transparent rounded-full animate-spin"></div>}
                               {s.status}
                            </span>
                         </td>
                       </tr>
                     ))
                   )}
                 </tbody>
               </table>
             </div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 sticky top-24">
              <div className="flex items-center gap-3 mb-6">
                <div className="p-2 bg-amber-100 text-amber-600 rounded-lg"><Send size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">New Request</h2>
                  <p className="text-sm text-slate-500">Submit adjustment to Registrar</p>
                </div>
              </div>

              <form onSubmit={handleSubmitRequest} className="space-y-5">
                <div className="space-y-2">
                  <label className="block text-sm font-bold text-slate-700">Target Student</label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                    <input
                      type="text"
                      placeholder="Type name or ID to filter..."
                      value={requestSearch}
                      onChange={(e) => setRequestSearch(e.target.value)}
                      className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-t-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-xs font-medium text-slate-500"
                    />
                  </div>
                  <select 
                    value={selectedStudentId}
                    onChange={(e) => setSelectedStudentId(e.target.value)}
                    className="w-full p-3 bg-white border border-t-0 border-slate-200 rounded-b-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all font-medium text-slate-700 text-sm"
                    size={5}
                  >
                    <option value="" disabled className="text-slate-400">Select from results...</option>
                    {filteredRequestStudents.length === 0 ? (
                      <option disabled>No students found</option>
                    ) : (
                      filteredRequestStudents.map(s => (
                        <option key={s.id} value={s.id}>{s.id} - {s.name}</option>
                      ))
                    )}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5">Request Type</label>
                  <div className="flex flex-col gap-2">
                    {(['Section Change', 'English Shift'] as const).map(type => (
                      <button
                        key={type}
                        type="button"
                        onClick={() => setRequestType(type)}
                        className={`p-3 text-sm font-bold rounded-xl border text-left transition-all ${
                          requestType === type 
                            ? 'bg-sky-600 border-sky-600 text-white shadow-md shadow-sky-100' 
                            : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                        }`}
                      >
                        {type}
                      </button>
                    ))}
                  </div>
                </div>

                {isPrepSectionChange && (
                  <div className="space-y-4 p-4 bg-sky-50 rounded-xl border border-sky-100 animate-in fade-in slide-in-from-top-2">
                    <div className="flex items-center gap-2 text-sky-700 font-bold text-xs uppercase mb-1">
                      <Info size={14} />
                      Prep Details Required
                    </div>
                    <div className="space-y-3">
                      <div>
                        <label className="block text-[10px] font-black text-sky-600 uppercase mb-1">Course Name</label>
                        <div className="relative">
                          <Book className="absolute left-3 top-1/2 -translate-y-1/2 text-sky-400" size={14} />
                          <select
                            value={courseName}
                            onChange={(e) => setCourseName(e.target.value)}
                            className="w-full pl-9 pr-3 py-2 bg-white border border-sky-200 rounded-lg text-sm font-semibold text-slate-500 focus:ring-2 focus:ring-sky-400 outline-none"
                          >
                            <option value="">Select Course...</option>
                            {COURSE_LIST.map(course => (
                              <option key={course} value={course}>{course}</option>
                            ))}
                          </select>
                        </div>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-sky-600 uppercase mb-1">Target Section</label>
                        <div className="relative">
                          <Hash className="absolute left-3 top-1/2 -translate-y-1/2 text-sky-400" size={14} />
                          <input
                            type="text"
                            placeholder="e.g. 104"
                            value={sectionNumber}
                            onChange={(e) => setSectionNumber(e.target.value)}
                            className="w-full pl-9 pr-3 py-2 bg-white border border-sky-200 rounded-lg text-sm font-semibold text-slate-500 focus:ring-2 focus:ring-sky-400 outline-none"
                          />
                        </div>
                      </div>
                    </div>
                  </div>
                )}

                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1.5">Specific Justification <span className="text-slate-400 font-normal">(Optional)</span></label>
                  <textarea
                    value={requestDetails}
                    onChange={(e) => setRequestDetails(e.target.value)}
                    placeholder="Provide additional details or reasons..."
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all h-24 resize-none text-slate-500 font-medium"
                  />
                </div>

                <button
                  type="submit"
                  disabled={isSubmitDisabled}
                  className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-slate-200 flex items-center justify-center gap-2"
                >
                  <Send size={18} />
                  Send to Registrar
                </button>
              </form>
            </div>
          </div>

          <div className="lg:col-span-2 space-y-6">
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
               <div className="flex items-center justify-between mb-8">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-100 text-slate-600 rounded-lg"><LayoutList size={24} /></div>
                    <h2 className="text-xl font-bold text-slate-900">Recent History</h2>
                  </div>
               </div>

               <div className="space-y-4">
                 {requests.length === 0 ? (
                   <div className="text-center py-20 bg-slate-50 rounded-2xl border border-dashed border-slate-200 text-slate-400">
                      <LayoutList size={40} className="mx-auto mb-4 opacity-20" />
                      <p className="font-medium">No adjustment requests submitted yet</p>
                   </div>
                 ) : (
                   requests.map((request) => (
                     <div key={request.id} className="bg-slate-50 rounded-2xl p-6 border border-slate-200 hover:bg-white hover:shadow-md transition-all">
                        <div className="flex justify-between items-start mb-4">
                           <div className="flex items-center gap-2">
                              <span className={`px-2.5 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                                request.status === 'Registered' ? 'bg-emerald-100 text-emerald-700' : 
                                request.status === 'Needs Revision' ? 'bg-amber-100 text-amber-700' :
                                'bg-slate-200 text-slate-600'
                              }`}>
                                {request.status === 'Registered' ? 'REGISTERED' : 
                                 request.status === 'Needs Revision' ? 'REVISION NEEDED' : 
                                 'PENDING REGISTRAR'}
                              </span>
                              <span className="text-[10px] font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-100">
                                #{request.id}
                              </span>
                           </div>
                           <span className="text-xs font-medium text-slate-400">
                             {new Date(request.createdAt).toLocaleDateString()} at {new Date(request.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                           </span>
                        </div>

                        <div className="mb-3">
                          <h4 className="font-black text-slate-900">{request.studentName} <span className="text-slate-400 text-sm font-normal">({request.studentId})</span></h4>
                          <span className="text-[11px] font-bold text-sky-600 bg-sky-50 px-2 py-0.5 rounded border border-sky-100 inline-block mt-1">
                            {request.requestType}
                          </span>
                        </div>

                        <p className="text-sm text-slate-600 leading-relaxed bg-white/50 p-3 rounded-xl border border-slate-100 italic">
                          "{request.details}"
                        </p>

                        {request.status === 'Registered' && (
                          <div className="mt-4 flex items-center gap-2 text-xs font-bold text-emerald-600">
                             <CheckCircle2 size={16} />
                             Registrar has officially registered this adjustment
                          </div>
                        )}

                        {request.status === 'Needs Revision' && (
                          <div className="mt-4 flex items-center gap-2 text-xs font-bold text-amber-600">
                             <RotateCcw size={16} />
                             Registrar requested a revision. Please review and update details.
                          </div>
                        )}
                     </div>
                   ))
                 )}
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PrepDashboard;

import React, { useState, useMemo } from 'react';
import { Student, AcademicLevel, RegistrationStatus, ScheduleRequest, ActivityLog } from '../types';
import { FileUp, Send, CheckCircle2, History, Info, LayoutList, MessageSquarePlus, Download, Search, Hash, Book, RotateCcw } from 'lucide-react';
import * as XLSX from 'xlsx';

interface PrepDashboardProps {
  students: Student[];
  setStudents: React.Dispatch<React.SetStateAction<Student[]>>;
  requests: ScheduleRequest[];
  setRequests: React.Dispatch<React.SetStateAction<ScheduleRequest[]>>;
  addLog: (type: ActivityLog['type'], description: string, actor: string, studentId?: string, studentName?: string) => void;
}

const COURSE_LIST = [
  'ENGL001', 'ENGL002', 'ENGL003', 'ENGL004', 'ENGL005', 
  'MATH001', 'MATH002', 'MATH012', 
  'PYP 001', 'PYP 002', 
  'Modular Courses', 
  'PE 001', 'PE 002'
];

const PrepDashboard: React.FC<PrepDashboardProps> = ({ students, setStudents, requests, setRequests, addLog }) => {
  const [activeTab, setActiveTab] = useState<'placement' | 'adjustments'>('placement');
  const [selectedStudentId, setSelectedStudentId] = useState('');
  const [requestType, setRequestType] = useState<'Section Change' | 'English Shift'>('Section Change');
  const [requestDetails, setRequestDetails] = useState('');

  const [sectionNumber, setSectionNumber] = useState('');
  const [courseName, setCourseName] = useState('');

  const [statusSearch, setStatusSearch] = useState('');
  const [requestSearch, setRequestSearch] = useState('');
  const [historySearch, setHistorySearch] = useState('');

  const selectedStudent = useMemo(() => 
    students.find(s => s.id === selectedStudentId), 
    [students, selectedStudentId]
  );

  const isPrepSectionChange = selectedStudent?.academicLevel === AcademicLevel.PREP && requestType === 'Section Change';

  const handlePlacementUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        setStudents(prev => {
          const updatedStudents = [...prev];
          let updateCount = 0;
          let newCount = 0;

          data.forEach((row: any) => {
            const rowId = String(row.ID || row.id || '');
            if (!rowId) return;

            const eng = String(row.English || row.english || 'ENGL001');
            const math = String(row.Math || row.math || 'MATH001');

            const engSec = row['English Section'] || row.english_section ? String(row['English Section'] || row.english_section) : undefined;
            const mathSec = row['Math Section'] || row.math_section ? String(row['Math Section'] || row.math_section) : undefined;

            const isPromoted = eng.toLowerCase() === 'promoted' && math.toLowerCase() === 'promoted';
            const level = isPromoted ? AcademicLevel.FRESHMAN : AcademicLevel.PREP;

            const existingIndex = updatedStudents.findIndex(s => s.id === rowId);

            const detailString = `English: ${eng} (Sec: ${engSec || 'N/A'}) | Math: ${math} (Sec: ${mathSec || 'N/A'})`;

            if (existingIndex !== -1) {
              updatedStudents[existingIndex] = {
                ...updatedStudents[existingIndex],
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec || updatedStudents[existingIndex].englishSection,
                mathSection: mathSec || updatedStudents[existingIndex].mathSection,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              };
              updateCount++;
              addLog('Placement', `Updated Data: ${detailString}. Status reset to Under Process.`, 'Prep Dept', rowId, updatedStudents[existingIndex].name);
            } else {
              const newName = String(row.Name || row.name || 'External Record');
              updatedStudents.push({
                id: rowId,
                name: newName,
                gender: 'Male',
                admittedMajor: 'Not Provided',
                term: '241',
                englishPlacement: eng,
                mathPlacement: math,
                academicLevel: level,
                englishSection: engSec,
                mathSection: mathSec,
                status: RegistrationStatus.UNDER_PROCESS,
                updatedAt: new Date().toISOString()
              });
              newCount++;
              addLog('Placement', `New Record: ${detailString}. Status: Under Process.`, 'Prep Dept', rowId, newName);
            }
          });

          alert(`Placement update complete: ${updateCount} students updated, ${newCount} new records created. All updated records reset to Under Process.`);
          return updatedStudents;
        });

      } catch (err) {
        console.error(err);
        alert("Error parsing file. Ensure columns include ID, English, Math, 'English Section', and 'Math Section'.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const downloadPlacementTemplate = () => {
    const templateData = [
      { ID: '20241001', English: 'Promoted', Math: 'MATH001', 'English Section': '45', 'Math Section': '55' },
      { ID: '20241002', English: 'ENGL001', Math: 'Promoted', 'English Section': '10', 'Math Section': '20' }
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Placements");
    XLSX.writeFile(wb, "Student_Placement_Template.xlsx");
  };

  const handleSubmitRequest = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStudent) {
      alert("Student ID not found.");
      return;
    }

    let finalDetails = requestDetails;
    if (isPrepSectionChange) {
      finalDetails = `[COURSE: ${courseName} | NEW SECTION: ${sectionNumber}]${requestDetails ? ' - ' + requestDetails : ''}`;
    }

    const newRequest: ScheduleRequest = {
      id: Math.random().toString(36).substr(2, 9),
      studentId: selectedStudent.id,
      studentName: selectedStudent.name,
      requestType,
      details: finalDetails || 'No justification provided.',
      courseName: isPrepSectionChange ? courseName : undefined,
      sectionNumber: isPrepSectionChange ? sectionNumber : undefined,
      status: 'Pending',
      createdAt: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    addLog('Adjustment', `Submitted ${requestType}: ${finalDetails || 'Request sent.'}`, 'Prep Dept', selectedStudent.id, selectedStudent.name);

    setRequestDetails('');
    setSectionNumber('');
    setCourseName('');
    setSelectedStudentId('');
    setRequestSearch('');
    alert("Schedule adjustment request sent to Registrar.");
  };

  const filteredStatusStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(statusSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(statusSearch.toLowerCase())
    );
  }, [students, statusSearch]);

  const filteredRequestStudents = useMemo(() => {
    return students.filter(s => 
      s.name.toLowerCase().includes(requestSearch.toLowerCase()) || 
      s.id.toLowerCase().includes(requestSearch.toLowerCase())
    );
  }, [students, requestSearch]);

  const filteredHistory = useMemo(() => {
    const search = historySearch.toLowerCase();
    return requests.filter(r => 
      r.studentName.toLowerCase().includes(search) ||
      r.studentId.toLowerCase().includes(search) ||
      r.requestType.toLowerCase().includes(search) ||
      r.details.toLowerCase().includes(search)
    );
  }, [requests, historySearch]);

  const isSubmitDisabled = !selectedStudentId || (isPrepSectionChange && (!sectionNumber || !courseName));

  return (
    <div className="space-y-6">
      <div className="flex gap-4 border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('placement')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'placement' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <FileUp size={18} />
          Placement Control
        </button>
        <button 
          onClick={() => setActiveTab('adjustments')}
          className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 ${
            activeTab === 'adjustments' ? 'border-sky-600 text-sky-600 bg-sky-50/50' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <MessageSquarePlus size={18} />
          Schedule Adjustments
        </button>
      </div>

      {activeTab === 'placement' ? (
        <div className="grid grid-cols-1 gap-8">
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-sky-100 text-sky-600 rounded-lg"><FileUp size={24} /></div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">Placement Processing</h2>
                  <p className="text-sm text-slate-500">Update existing students with test results</p>
                </div>
              </div>
              <button 
                onClick={downloadPlacementTemplate}
                className="flex items-center gap-2 text-xs font-bold text-sky-600 bg-sky-50 px-3 py-2 rounded-lg hover:bg-sky-100 transition-colors"
              >
                <Download size={14} />
                Download Placement Template
              </button>
            </div>

            <div className="grid grid-cols-1 gap-8">
              <div className="border-2 border-dashed border-slate-200 rounded-2xl p-10 text-center space-y-4 hover:border-sky-300 transition-colors bg-slate-50/30 group">
                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto text-slate-400 shadow-sm border border-slate-100 group-hover:scale-110 transition-transform">
                  <FileUp size={32} className="group-hover:text-sky-500" />
                </div>
                <div>
                  <p className="font-semibold text-slate-700">Drop Placement Excel here</p>
                  <p className="text-sm text-slate-400">Include 'English Section' and 'Math Section' columns</p>
                </div>
                <label className="inline-block px-6 py-3 bg-slate-900 text-white rounded-xl cursor-pointer hover:bg-slate-800 transition-all font-medium shadow-lg shadow-slate-200">
                  Import Test Results
                  <input type="file" className="hidden" onChange={handlePlacementUpload} accept=".xlsx, .xls, .csv" />
                </label>
              </div>
            </div>
          </div>

          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
             <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><History size={24} /></div>
                  <h2 className="text-xl font-bold text-slate-900">Live Status Monitor</h2>
                </div>
                <div className="relative w-full md:w-72">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <input
                    type="text"
                    placeholder="Search student by Name or ID..."
                    value={statusSearch}
                    onChange={(e) => setStatusSearch(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none transition-all text-sm font-medium text-slate-400"
                  />
                </div>
             </div>

             <div className="overflow-x-auto rounded-xl border border-slate-100">
               <table className="w-full text-left">
                 <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                   <tr>
                     <th className="px-6 py-4">Student</th>
                     <th className="px-6 py-4">Placement</th>
                     <th className="px-6 py-4">Section Number</th>
                     <th className="px-6 py-4">Academic Level</th>
                     <th className="px-6 py-4 text-center">Status</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                   {filteredStatusStudents.length === 0 ? (
                     <tr>
                       <td colSpan={5} className="px-6 py-12 text-center text-slate-400 font-medium">
                         No students found matching your search.
                       </td>
                     </tr>
                   ) : (
                     filteredStatusStudents.map(s => (
                       <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                         <td className="px-6 py-4">
                            <div className="font-bold text-slate-900">{s.name}</div>
                            <div className="text-xs text-slate-400 font-mono font-bold uppercase">{s.id}</div>
                         </td>
                         <td className="px-6 py-4">
                            <div className="flex gap-2">
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">E: {s.englishPlacement}</span>
                               <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] border border-slate-200 font-bold text-slate-600">M: {s.mathPlacement}</span>
                            </div>
